export interface User {
  id: string;
  name: string;
  email: string;
  avatar?: string;
}

export interface Document {
  id: string;
  userId: string;
  title: string;
  filePath: string;
  extractedText: string;
  summary?: string;
  createdAt: number;
}

export interface Flashcard {
  id: string;
  question: string;
  answer: string;
  isStarred: boolean;
  isReviewed: boolean;
  difficulty: 'easy' | 'medium' | 'hard';
}

export interface FlashcardSet {
  id: string;
  documentId: string;
  title: string;
  cards: Flashcard[];
  createdAt: number;
}

export interface QuizQuestion {
  id: string;
  question: string;
  options: string[];
  correctIndex: number;
  explanation: string;
}

export interface Quiz {
  id: string;
  documentId: string;
  title: string;
  questions: QuizQuestion[];
  score?: number;
  attemptedAt?: number;
}

export interface Activity {
  id: string;
  type: 'upload' | 'flashcard' | 'quiz' | 'chat';
  description: string;
  timestamp: number;
}

export interface ChatMessage {
  role: 'user' | 'model';
  content: string;
  timestamp: number;
}

import { User, Document, FlashcardSet, Quiz, Activity, ChatMessage } from '../types';

const STORAGE_KEYS = {
  USER: 'ai_learn_user',
  DOCS: 'ai_learn_docs',
  SETS: 'ai_learn_sets',
  QUIZZES: 'ai_learn_quizzes',
  ACTIVITY: 'ai_learn_activity',
  CHATS: 'ai_learn_chats'
};

export const storageService = {
  // Auth
  getUser: (): User | null => {
    const data = localStorage.getItem(STORAGE_KEYS.USER);
    return data ? JSON.parse(data) : null;
  },
  setUser: (user: User | null) => {
    if (user) localStorage.setItem(STORAGE_KEYS.USER, JSON.stringify(user));
    else localStorage.removeItem(STORAGE_KEYS.USER);
  },

  // Documents
  getDocuments: (): Document[] => {
    const data = localStorage.getItem(STORAGE_KEYS.DOCS);
    return data ? JSON.parse(data) : [];
  },
  saveDocument: (doc: Document) => {
    const docs = storageService.getDocuments();
    docs.push(doc);
    localStorage.setItem(STORAGE_KEYS.DOCS, JSON.stringify(docs));
    storageService.addActivity({
      id: Math.random().toString(36).substr(2, 9),
      type: 'upload',
      description: `Uploaded document: ${doc.title}`,
      timestamp: Date.now()
    });
  },
  updateDocument: (id: string, updates: Partial<Document>) => {
    const docs = storageService.getDocuments();
    const index = docs.findIndex(d => d.id === id);
    if (index !== -1) {
      docs[index] = { ...docs[index], ...updates };
      localStorage.setItem(STORAGE_KEYS.DOCS, JSON.stringify(docs));
    }
  },

  // Flashcards
  getFlashcardSets: (): FlashcardSet[] => {
    const data = localStorage.getItem(STORAGE_KEYS.SETS);
    return data ? JSON.parse(data) : [];
  },
  saveFlashcardSet: (set: FlashcardSet) => {
    const sets = storageService.getFlashcardSets();
    sets.push(set);
    localStorage.setItem(STORAGE_KEYS.SETS, JSON.stringify(sets));
    storageService.addActivity({
      id: Math.random().toString(36).substr(2, 9),
      type: 'flashcard',
      description: `Generated flashcards for: ${set.title}`,
      timestamp: Date.now()
    });
  },
  updateFlashcardSet: (id: string, updates: Partial<FlashcardSet>) => {
    const sets = storageService.getFlashcardSets();
    const index = sets.findIndex(s => s.id === id);
    if (index !== -1) {
      sets[index] = { ...sets[index], ...updates };
      localStorage.setItem(STORAGE_KEYS.SETS, JSON.stringify(sets));
    }
  },

  // Quizzes
  getQuizzes: (): Quiz[] => {
    const data = localStorage.getItem(STORAGE_KEYS.QUIZZES);
    return data ? JSON.parse(data) : [];
  },
  saveQuiz: (quiz: Quiz) => {
    const quizzes = storageService.getQuizzes();
    quizzes.push(quiz);
    localStorage.setItem(STORAGE_KEYS.QUIZZES, JSON.stringify(quizzes));
  },
  updateQuiz: (id: string, updates: Partial<Quiz>) => {
    const quizzes = storageService.getQuizzes();
    const index = quizzes.findIndex(q => q.id === id);
    if (index !== -1) {
      quizzes[index] = { ...quizzes[index], ...updates };
      localStorage.setItem(STORAGE_KEYS.QUIZZES, JSON.stringify(quizzes));
      if (updates.score !== undefined) {
        storageService.addActivity({
          id: Math.random().toString(36).substr(2, 9),
          type: 'quiz',
          description: `Completed quiz: ${quizzes[index].title} with score ${updates.score}%`,
          timestamp: Date.now()
        });
      }
    }
  },

  // Chats
  getChats: (docId: string): ChatMessage[] => {
    const chats = localStorage.getItem(`${STORAGE_KEYS.CHATS}_${docId}`);
    return chats ? JSON.parse(chats) : [];
  },
  saveChatMessage: (docId: string, message: ChatMessage) => {
    const chats = storageService.getChats(docId);
    chats.push(message);
    localStorage.setItem(`${STORAGE_KEYS.CHATS}_${docId}`, JSON.stringify(chats));
  },

  // Activity
  getActivities: (): Activity[] => {
    const data = localStorage.getItem(STORAGE_KEYS.ACTIVITY);
    return data ? JSON.parse(data) : [];
  },
  addActivity: (activity: Activity) => {
    const activities = storageService.getActivities();
    activities.unshift(activity);
    localStorage.setItem(STORAGE_KEYS.ACTIVITY, JSON.stringify(activities.slice(0, 20)));
  }
};

import { GoogleGenAI, Type } from "@google/genai";

const API_KEY = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const geminiService = {
  generateSummary: async (text: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Summarize the following educational content in a structured way with key takeaways: ${text.substring(0, 10000)}`,
      config: {
        systemInstruction: "You are an expert academic summarizer. Provide a concise, professional summary."
      }
    });
    return response.text;
  },

  chatWithDocument: async (text: string, history: {role: string, content: string}[], message: string) => {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: `You are a learning assistant. Answer the user's question based ONLY on the following context: ${text.substring(0, 10000)}. If the answer is not in the document, say you don't know.`
      }
    });

    // We handle history manually for this simplified mock
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        { role: 'user', parts: [{ text: `Context: ${text.substring(0, 5000)}` }] },
        ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.content }] })),
        { role: 'user', parts: [{ text: message }] }
      ]
    });
    return response.text;
  },

  generateFlashcards: async (text: string, count: number = 5) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create ${count} flashcards from the following text. Return as JSON. Text: ${text.substring(0, 8000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              answer: { type: Type.STRING },
              difficulty: { type: Type.STRING, enum: ['easy', 'medium', 'hard'] }
            },
            required: ['question', 'answer', 'difficulty']
          }
        }
      }
    });
    return JSON.parse(response.text || "[]");
  },

  generateQuiz: async (text: string, count: number = 5) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create a ${count} question multiple-choice quiz from the following text. Include explanations for each question. Return as JSON. Text: ${text.substring(0, 8000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctIndex: { type: Type.NUMBER },
              explanation: { type: Type.STRING }
            },
            required: ['question', 'options', 'correctIndex', 'explanation']
          }
        }
      }
    });
    return JSON.parse(response.text || "[]");
  }
};

import React, { useState, useEffect, createContext, useContext } from 'react';
