import React, { useState, useRef } from 'react';
import { Plus, FileText, Search, MoreVertical, ExternalLink, Trash2, Clock } from 'lucide-react';
import { storageService } from '../services/storageService';
import { Document } from '../types';
import { Link } from 'react-router-dom';

const Documents: React.FC = () => {
  const [docs, setDocs] = useState<Document[]>(storageService.getDocuments());
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || file.type !== 'application/pdf') {
      alert('Please upload a valid PDF file.');
      return;
    }

    setIsUploading(true);
    // Simulate reading PDF text
    setTimeout(() => {
      const newDoc: Document = {
        id: Math.random().toString(36).substr(2, 9),
        userId: '1',
        title: file.name.replace('.pdf', ''),
        filePath: URL.createObjectURL(file),
        extractedText: `Simulated extracted text for ${file.name}. This is a comprehensive guide to machine learning concepts including supervised, unsupervised, and reinforcement learning...`,
        createdAt: Date.now()
      };
      storageService.saveDocument(newDoc);
      setDocs([...docs, newDoc]);
      setIsUploading(false);
    }, 1500);
  };

  const deleteDoc = (id: string) => {
    if (confirm('Are you sure you want to delete this document?')) {
      const updated = docs.filter(d => d.id !== id);
      localStorage.setItem('ai_learn_docs', JSON.stringify(updated));
      setDocs(updated);
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold">My Documents</h1>
          <p className="text-gray-500">Upload and manage your study materials.</p>
        </div>
        <button 
          onClick={() => fileInputRef.current?.click()}
          disabled={isUploading}
          className="bg-green-600 hover:bg-green-700 disabled:bg-gray-400 text-white px-4 py-2 rounded-lg font-medium flex items-center justify-center gap-2 transition-colors"
        >
          {isUploading ? (
            <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
          ) : (
            <Plus size={20} />
          )}
          {isUploading ? 'Extracting...' : 'Upload PDF'}
        </button>
        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept=".pdf" 
          onChange={handleFileUpload} 
        />
      </div>

      <div className="bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">
        <div className="p-4 border-b border-gray-100 bg-gray-50/50 flex items-center gap-3">
          <Search size={18} className="text-gray-400" />
          <input 
            type="text" 
            placeholder="Filter documents..." 
            className="bg-transparent border-none outline-none text-sm w-full"
          />
        </div>

        <div className="divide-y divide-gray-100">
          {docs.length > 0 ? docs.map((doc) => (
            <div key={doc.id} className="p-4 hover:bg-gray-50 transition-colors flex items-center justify-between group">
              <div className="flex items-center gap-4 min-w-0">
                <div className="w-12 h-12 bg-red-50 text-red-500 rounded-lg flex items-center justify-center flex-shrink-0">
                  <FileText size={24} />
                </div>
                <div className="min-w-0">
                  <h3 className="font-semibold text-gray-900 truncate">{doc.title}</h3>
                  <div className="flex items-center gap-3 text-xs text-gray-500 mt-1">
                    <span className="flex items-center gap-1">
                      <Clock size={12} /> {new Date(doc.createdAt).toLocaleDateString()}
                    </span>
                    <span>1.2 MB</span>
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <Link 
                  to={`/documents/${doc.id}`}
                  className="p-2 text-gray-400 hover:text-green-600 hover:bg-green-50 rounded-lg transition-colors"
                  title="Open"
                >
                  <ExternalLink size={20} />
                </Link>
                <button 
                  onClick={() => deleteDoc(doc.id)}
                  className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                  title="Delete"
                >
                  <Trash2 size={20} />
                </button>
              </div>
            </div>
          )) : (
            <div className="p-12 text-center text-gray-500">
              <FileText size={48} className="mx-auto mb-4 text-gray-200" />
              <p>No documents uploaded yet.</p>
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="text-green-600 font-medium hover:underline mt-2"
              >
                Upload your first PDF
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Documents;

import React, { useState, useEffect, useRef } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
  FileText, MessageSquare, Sparkles, BookOpen, Target, 
  ChevronLeft, Send, Sparkle, Star, CheckCircle, 
  RotateCcw, ChevronRight, XCircle
} from 'lucide-react';
import { storageService } from '../services/storageService';
import { geminiService } from '../services/geminiService';
import { Document, ChatMessage, FlashcardSet, Quiz } from '../types';

const DocumentDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [doc, setDoc] = useState<Document | null>(null);
  const [activeTab, setActiveTab] = useState<'content' | 'chat' | 'actions' | 'flashcards' | 'quiz'>('content');
  const [isLoading, setIsLoading] = useState(false);

  // Chat State
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Flashcard State
  const [flashcardSets, setFlashcardSets] = useState<FlashcardSet[]>([]);
  const [currentSetIdx, setCurrentSetIdx] = useState(0);
  const [cardIdx, setCardIdx] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  // Quiz State
  const [activeQuiz, setActiveQuiz] = useState<Quiz | null>(null);
  const [quizStep, setQuizStep] = useState(0);
  const [userAnswers, setUserAnswers] = useState<number[]>([]);
  const [showResults, setShowResults] = useState(false);

  useEffect(() => {
    if (id) {
      const found = storageService.getDocuments().find(d => d.id === id);
      if (found) {
        setDoc(found);
        setMessages(storageService.getChats(id));
        setFlashcardSets(storageService.getFlashcardSets().filter(s => s.documentId === id));
      }
    }
  }, [id]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSendMessage = async () => {
    if (!input.trim() || !doc) return;
    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    storageService.saveChatMessage(doc.id, userMsg);
    setInput('');
    setIsLoading(true);

    try {
      const history = messages.map(m => ({ role: m.role, content: m.content }));
      const response = await geminiService.chatWithDocument(doc.extractedText, history, input);
      const aiMsg: ChatMessage = { role: 'model', content: response || "I couldn't process that.", timestamp: Date.now() };
      setMessages(prev => [...prev, aiMsg]);
      storageService.saveChatMessage(doc.id, aiMsg);
    } finally {
      setIsLoading(false);
    }
  };

  const generateSummary = async () => {
    if (!doc) return;
    setIsLoading(true);
    try {
      const summary = await geminiService.generateSummary(doc.extractedText);
      storageService.updateDocument(doc.id, { summary: summary || "" });
      setDoc(prev => prev ? { ...prev, summary: summary || "" } : null);
    } finally {
      setIsLoading(false);
    }
  };

  const generateFlashcards = async () => {
    if (!doc) return;
    setIsLoading(true);
    try {
      const cards = await geminiService.generateFlashcards(doc.extractedText);
      const newSet: FlashcardSet = {
        id: Math.random().toString(36).substr(2, 9),
        documentId: doc.id,
        title: `Cards from ${doc.title}`,
        cards: cards.map((c: any) => ({
          ...c,
          id: Math.random().toString(36).substr(2, 9),
          isStarred: false,
          isReviewed: false
        })),
        createdAt: Date.now()
      };
      storageService.saveFlashcardSet(newSet);
      setFlashcardSets(prev => [...prev, newSet]);
      alert('Flashcards generated successfully!');
    } finally {
      setIsLoading(false);
    }
  };

  const generateQuiz = async () => {
    if (!doc) return;
    setIsLoading(true);
    try {
      const questions = await geminiService.generateQuiz(doc.extractedText);
      const newQuiz: Quiz = {
        id: Math.random().toString(36).substr(2, 9),
        documentId: doc.id,
        title: `Quiz for ${doc.title}`,
        questions: questions.map((q: any) => ({ ...q, id: Math.random().toString(36).substr(2, 9) }))
      };
      storageService.saveQuiz(newQuiz);
      setActiveQuiz(newQuiz);
      setUserAnswers(new Array(newQuiz.questions.length).fill(-1));
      setQuizStep(0);
      setShowResults(false);
    } finally {
      setIsLoading(false);
    }
  };

  const submitQuiz = () => {
    if (!activeQuiz) return;
    let correct = 0;
    activeQuiz.questions.forEach((q, i) => {
      if (userAnswers[i] === q.correctIndex) correct++;
    });
    const score = Math.round((correct / activeQuiz.questions.length) * 100);
    storageService.updateQuiz(activeQuiz.id, { score, attemptedAt: Date.now() });
    setShowResults(true);
  };

  if (!doc) return <div>Document not found.</div>;

  return (
    <div className="max-w-6xl mx-auto h-full flex flex-col gap-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <Link to="/documents" className="p-2 text-gray-400 hover:bg-gray-100 rounded-lg">
            <ChevronLeft size={20} />
          </Link>
          <div>
            <h1 className="text-xl font-bold flex items-center gap-2">
              <FileText className="text-red-500" />
              {doc.title}
            </h1>
            <p className="text-xs text-gray-500 mt-0.5">Uploaded {new Date(doc.createdAt).toLocaleDateString()}</p>
          </div>
        </div>
      </div>

      {/* Tabs Nav */}
      <div className="flex items-center border-b border-gray-200 gap-2 overflow-x-auto">
        {[
          { id: 'content', icon: FileText, label: 'Content' },
          { id: 'chat', icon: MessageSquare, label: 'Chat' },
          { id: 'actions', icon: Sparkles, label: 'AI Actions' },
          { id: 'flashcards', icon: BookOpen, label: 'Flashcards' },
          { id: 'quiz', icon: Target, label: 'Quiz' },
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex items-center gap-2 px-4 py-3 text-sm font-medium transition-colors border-b-2 whitespace-nowrap ${
              activeTab === tab.id ? 'border-green-600 text-green-600' : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            <tab.icon size={18} />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Tab Content */}
      <div className="flex-1 bg-white border border-gray-200 rounded-xl shadow-sm overflow-hidden relative">
        {isLoading && (
          <div className="absolute inset-0 bg-white/70 backdrop-blur-sm z-50 flex flex-col items-center justify-center">
            <div className="w-12 h-12 border-4 border-green-100 border-t-green-600 rounded-full animate-spin mb-4" />
            <p className="text-green-800 font-medium">AI is working its magic...</p>
          </div>
        )}

        {/* Content Tab */}
        {activeTab === 'content' && (
          <div className="h-full p-8 overflow-y-auto">
            <div className="max-w-3xl mx-auto space-y-6">
              <div className="bg-gray-50 p-6 rounded-lg border border-gray-200">
                <h3 className="font-bold mb-4 uppercase text-xs tracking-wider text-gray-400">PDF TEXT PREVIEW</h3>
                <p className="text-gray-800 leading-relaxed whitespace-pre-wrap">{doc.extractedText}</p>
              </div>
            </div>
          </div>
        )}

        {/* Chat Tab */}
        {activeTab === 'chat' && (
          <div className="h-full flex flex-col">
            <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-4 bg-gray-50">
              {messages.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center p-8">
                  <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-4">
                    <MessageSquare size={32} />
                  </div>
                  <h3 className="text-lg font-bold">Ask anything about this document</h3>
                  <p className="text-gray-500 max-w-sm mt-2">Our AI assistant is ready to help you understand complex concepts within your document.</p>
                </div>
              )}
              {messages.map((msg, i) => (
                <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] rounded-2xl px-4 py-3 shadow-sm ${
                    msg.role === 'user' 
                      ? 'bg-green-600 text-white rounded-br-none' 
                      : 'bg-white text-gray-800 rounded-bl-none border border-gray-100'
                  }`}>
                    <p className="text-sm leading-relaxed">{msg.content}</p>
                    <p className={`text-[10px] mt-1 opacity-60 ${msg.role === 'user' ? 'text-green-100' : 'text-gray-400'}`}>
                      {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </p>
                  </div>
                </div>
              ))}
              <div ref={chatEndRef} />
            </div>
            <div className="p-4 border-t border-gray-200 bg-white flex gap-3">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                placeholder="Ask a question..."
                className="flex-1 bg-gray-100 border-none rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-green-500 transition-all"
              />
              <button 
                onClick={handleSendMessage}
                disabled={!input.trim()}
                className="bg-green-600 text-white p-2.5 rounded-xl hover:bg-green-700 disabled:bg-gray-300 transition-colors"
              >
                <Send size={20} />
              </button>
            </div>
          </div>
        )}

        {/* AI Actions Tab */}
        {activeTab === 'actions' && (
          <div className="h-full p-8 overflow-y-auto">
            <div className="max-w-2xl mx-auto space-y-8">
              <div className="bg-gradient-to-br from-green-50 to-blue-50 p-6 rounded-2xl border border-green-100 flex items-start gap-4">
                <div className="p-3 bg-white rounded-xl shadow-sm text-green-600">
                  <Sparkle />
                </div>
                <div className="flex-1">
                  <h3 className="font-bold text-lg mb-1">Generate AI Summary</h3>
                  <p className="text-gray-600 text-sm mb-4">Get a structured breakdown of the key concepts and takeaways from this document.</p>
                  <button 
                    onClick={generateSummary}
                    className="bg-green-600 text-white px-5 py-2 rounded-lg font-medium text-sm hover:bg-green-700 transition-all shadow-md active:scale-95"
                  >
                    Generate Now
                  </button>
                </div>
              </div>

              {doc.summary && (
                <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm animate-in fade-in slide-in-from-bottom-4">
                  <div className="flex items-center gap-2 text-green-600 mb-4">
                    <Sparkles size={20} />
                    <h4 className="font-bold uppercase text-xs tracking-wider">AI Generated Summary</h4>
                  </div>
                  <div className="prose prose-sm max-w-none text-gray-700 leading-relaxed whitespace-pre-wrap">
                    {doc.summary}
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {/* Flashcards Tab */}
        {activeTab === 'flashcards' && (
          <div className="h-full p-8 flex flex-col items-center overflow-y-auto">
            {flashcardSets.length === 0 ? (
              <div className="text-center py-12">
                <BookOpen size={64} className="mx-auto text-gray-200 mb-4" />
                <h3 className="text-xl font-bold mb-2">No flashcards yet</h3>
                <p className="text-gray-500 mb-6">Let AI scan your document and create study cards for you.</p>
                <button onClick={generateFlashcards} className="bg-green-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-green-700 shadow-lg active:scale-95 transition-all">
                  Generate Flashcards
                </button>
              </div>
            ) : (
              <div className="w-full max-w-lg space-y-8">
                <div className="flex items-center justify-between">
                  <h3 className="font-bold text-lg">{flashcardSets[currentSetIdx].title}</h3>
                  <span className="text-sm text-gray-500">{cardIdx + 1} / {flashcardSets[currentSetIdx].cards.length}</span>
                </div>

                <div className={`perspective-1000 w-full aspect-[4/3] cursor-pointer group ${isFlipped ? 'flashcard-flipped' : ''}`} onClick={() => setIsFlipped(!isFlipped)}>
                  <div className="flashcard-inner relative w-full h-full text-center transition-transform duration-500 shadow-xl rounded-2xl">
                    {/* Front */}
                    <div className="flashcard-front absolute inset-0 w-full h-full bg-white border-2 border-green-100 rounded-2xl flex flex-col items-center justify-center p-8">
                      <p className="text-gray-400 text-xs font-bold uppercase tracking-widest mb-4">QUESTION</p>
                      <h4 className="text-xl font-semibold text-gray-800 leading-relaxed">{flashcardSets[currentSetIdx].cards[cardIdx].question}</h4>
                      <p className="mt-auto text-xs text-gray-400">Click to flip</p>
                    </div>
                    {/* Back */}
                    <div className="flashcard-back absolute inset-0 w-full h-full bg-green-600 text-white rounded-2xl flex flex-col items-center justify-center p-8">
                      <p className="text-green-200 text-xs font-bold uppercase tracking-widest mb-4">ANSWER</p>
                      <p className="text-lg font-medium leading-relaxed">{flashcardSets[currentSetIdx].cards[cardIdx].answer}</p>
                      <p className="mt-auto text-xs text-green-200">Click to show question</p>
                    </div>
                  </div>
                </div>

                <div className="flex items-center justify-center gap-6">
                  <button 
                    disabled={cardIdx === 0}
                    onClick={() => { setCardIdx(cardIdx - 1); setIsFlipped(false); }}
                    className="w-12 h-12 flex items-center justify-center bg-gray-100 text-gray-600 rounded-full disabled:opacity-30 hover:bg-gray-200 transition-colors"
                  >
                    <ChevronLeft />
                  </button>
                  <button 
                    onClick={() => {
                      const updated = [...flashcardSets];
                      updated[currentSetIdx].cards[cardIdx].isStarred = !updated[currentSetIdx].cards[cardIdx].isStarred;
                      setFlashcardSets(updated);
                      storageService.updateFlashcardSet(updated[currentSetIdx].id, { cards: updated[currentSetIdx].cards });
                    }}
                    className={`w-12 h-12 flex items-center justify-center rounded-full transition-colors ${
                      flashcardSets[currentSetIdx].cards[cardIdx].isStarred ? 'bg-yellow-100 text-yellow-500' : 'bg-gray-100 text-gray-400'
                    }`}
                  >
                    <Star fill={flashcardSets[currentSetIdx].cards[cardIdx].isStarred ? 'currentColor' : 'none'} />
                  </button>
                  <button 
                    disabled={cardIdx === flashcardSets[currentSetIdx].cards.length - 1}
                    onClick={() => { setCardIdx(cardIdx + 1); setIsFlipped(false); }}
                    className="w-12 h-12 flex items-center justify-center bg-green-600 text-white rounded-full disabled:bg-gray-200 hover:bg-green-700 transition-colors"
                  >
                    <ChevronRight />
                  </button>
                </div>

                <div className="text-center">
                  <button onClick={generateFlashcards} className="text-sm text-green-600 font-medium hover:underline">
                    Regenerate a new set
                  </button>
                </div>
              </div>
            )}
          </div>
        )}

        {/* Quiz Tab */}
        {activeTab === 'quiz' && (
          <div className="h-full p-8 overflow-y-auto">
            {!activeQuiz ? (
              <div className="max-w-md mx-auto text-center py-12">
                <Target size={64} className="mx-auto text-gray-200 mb-4" />
                <h3 className="text-xl font-bold mb-2">Ready to test yourself?</h3>
                <p className="text-gray-500 mb-8">AI will create a custom multiple-choice quiz based on the key facts in your document.</p>
                <div className="grid grid-cols-2 gap-4 mb-8">
                  <div className="p-4 border border-gray-100 rounded-xl bg-gray-50">
                    <span className="block text-2xl font-bold">5</span>
                    <span className="text-xs text-gray-500 uppercase font-bold">Questions</span>
                  </div>
                  <div className="p-4 border border-gray-100 rounded-xl bg-gray-50">
                    <span className="block text-2xl font-bold">MCQ</span>
                    <span className="text-xs text-gray-500 uppercase font-bold">Format</span>
                  </div>
                </div>
                <button onClick={generateQuiz} className="w-full bg-green-600 text-white py-4 rounded-xl font-bold shadow-lg hover:bg-green-700 transition-all active:scale-95">
                  Generate Quiz
                </button>
              </div>
            ) : showResults ? (
              <div className="max-w-2xl mx-auto space-y-8 animate-in zoom-in-95 duration-300">
                <div className="text-center p-8 bg-green-50 rounded-3xl border border-green-100">
                  <div className="w-20 h-20 bg-green-600 text-white rounded-full flex items-center justify-center text-2xl font-bold mx-auto mb-4 shadow-xl">
                    {activeQuiz.score}%
                  </div>
                  <h2 className="text-2xl font-bold text-green-800">Quiz Completed!</h2>
                  <p className="text-green-700 mt-2">You scored better than 75% of typical learners on this material.</p>
                </div>

                <div className="space-y-6">
                  <h3 className="font-bold border-b pb-2">Detailed Review</h3>
                  {activeQuiz.questions.map((q, i) => (
                    <div key={q.id} className={`p-6 rounded-2xl border ${userAnswers[i] === q.correctIndex ? 'bg-white border-gray-200' : 'bg-red-50 border-red-100'}`}>
                      <div className="flex items-start gap-4">
                        <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 font-bold ${
                          userAnswers[i] === q.correctIndex ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'
                        }`}>
                          {i + 1}
                        </div>
                        <div className="flex-1">
                          <p className="font-bold text-gray-900 mb-4">{q.question}</p>
                          <div className="space-y-2">
                            {q.options.map((opt, optIdx) => (
                              <div key={optIdx} className={`p-3 rounded-lg text-sm border flex items-center justify-between ${
                                optIdx === q.correctIndex ? 'bg-green-100 border-green-200 text-green-800 font-medium' :
                                optIdx === userAnswers[i] ? 'bg-red-100 border-red-200 text-red-800' : 'bg-white border-gray-100 text-gray-600'
                              }`}>
                                {opt}
                                {optIdx === q.correctIndex && <CheckCircle size={16} />}
                                {optIdx === userAnswers[i] && optIdx !== q.correctIndex && <XCircle size={16} />}
                              </div>
                            ))}
                          </div>
                          <div className="mt-4 p-4 bg-gray-50 rounded-xl text-xs text-gray-600 italic">
                            <span className="font-bold block mb-1 not-italic">EXPLANATION:</span>
                            {q.explanation}
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="flex gap-4 pb-12">
                  <button onClick={() => { setActiveQuiz(null); setQuizStep(0); setShowResults(false); }} className="flex-1 flex items-center justify-center gap-2 border border-gray-200 py-3 rounded-xl font-bold hover:bg-gray-50 transition-colors">
                    <RotateCcw size={18} /> New Quiz
                  </button>
                </div>
              </div>
            ) : (
              <div className="max-w-xl mx-auto space-y-8">
                <div className="flex items-center justify-between">
                  <span className="text-sm font-bold text-green-600 uppercase tracking-widest">Question {quizStep + 1} of {activeQuiz.questions.length}</span>
                  <div className="w-48 h-2 bg-gray-100 rounded-full overflow-hidden">
                    <div className="h-full bg-green-600 transition-all" style={{ width: `${((quizStep + 1) / activeQuiz.questions.length) * 100}%` }}></div>
                  </div>
                </div>

                <div className="space-y-6">
                  <h2 className="text-xl font-bold leading-relaxed">{activeQuiz.questions[quizStep].question}</h2>
                  <div className="space-y-3">
                    {activeQuiz.questions[quizStep].options.map((option, idx) => (
                      <button
                        key={idx}
                        onClick={() => {
                          const updated = [...userAnswers];
                          updated[quizStep] = idx;
                          setUserAnswers(updated);
                        }}
                        className={`w-full text-left p-4 rounded-xl border-2 transition-all group flex items-center justify-between ${
                          userAnswers[quizStep] === idx ? 'border-green-600 bg-green-50 shadow-md ring-2 ring-green-100' : 'border-gray-100 hover:border-green-200 hover:bg-gray-50'
                        }`}
                      >
                        <span className={`font-medium ${userAnswers[quizStep] === idx ? 'text-green-800' : 'text-gray-700'}`}>{option}</span>
                        <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${userAnswers[quizStep] === idx ? 'border-green-600 bg-green-600' : 'border-gray-300'}`}>
                          {userAnswers[quizStep] === idx && <div className="w-2 h-2 rounded-full bg-white"></div>}
                        </div>
                      </button>
                    ))}
                  </div>
                </div>

                <div className="flex items-center justify-between pt-8">
                  <button 
                    disabled={quizStep === 0}
                    onClick={() => setQuizStep(quizStep - 1)}
                    className="px-6 py-2 text-gray-500 font-bold disabled:opacity-30 hover:underline"
                  >
                    PREVIOUS
                  </button>
                  {quizStep === activeQuiz.questions.length - 1 ? (
                    <button 
                      onClick={submitQuiz}
                      disabled={userAnswers[quizStep] === -1}
                      className="bg-green-600 text-white px-10 py-3 rounded-xl font-bold shadow-lg hover:bg-green-700 transition-all disabled:bg-gray-300"
                    >
                      FINISH QUIZ
                    </button>
                  ) : (
                    <button 
                      onClick={() => setQuizStep(quizStep + 1)}
                      disabled={userAnswers[quizStep] === -1}
                      className="bg-green-600 text-white px-10 py-3 rounded-xl font-bold shadow-lg hover:bg-green-700 transition-all disabled:bg-gray-300"
                    >
                      NEXT
                    </button>
                  )}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

