              >
                {isLogin ? 'Sign Up' : 'Sign In'}
              </button>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Auth;

import { GoogleGenAI, Type } from "@google/genai";

// Initialize the Gemini AI client using the API key directly from environment variables
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  generateSummary: async (text: string) => {
    // Basic text task, using gemini-3-flash-preview
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Summarize the following educational content in a structured way with key takeaways: ${text.substring(0, 10000)}`,
      config: {
        systemInstruction: "You are an expert academic summarizer. Provide a concise, professional summary."
      }
    });
    // Property access .text as per guidelines
    return response.text;
  },

  chatWithDocument: async (text: string, history: {role: string, content: string}[], message: string) => {
    // Calling generateContent directly with model and history
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        { role: 'user', parts: [{ text: `Context: ${text.substring(0, 5000)}` }] },
        ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.content }] })),
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: `You are a learning assistant. Answer the user's question based ONLY on the following context. If the answer is not in the document, say you don't know.`
      }
    });
    return response.text;
  },

  generateFlashcards: async (text: string, count: number = 5) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create ${count} flashcards from the following text. Return as JSON. Text: ${text.substring(0, 8000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              answer: { type: Type.STRING },
              difficulty: { type: Type.STRING, enum: ['easy', 'medium', 'hard'] }
            },
            required: ['question', 'answer', 'difficulty']
          }
        }
      }
    });
    return JSON.parse(response.text || "[]");
  },

  generateQuiz: async (text: string, count: number = 5) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create a ${count} question multiple-choice quiz from the following text. Include explanations for each question. Return as JSON. Text: ${text.substring(0, 8000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctIndex: { type: Type.NUMBER },
              explanation: { type: Type.STRING }
            },
            required: ['question', 'options', 'correctIndex', 'explanation']
          }
        }
      }
    });
    return JSON.parse(response.text || "[]");
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
  FileText, MessageSquare, Sparkles, BookOpen, Target, 
  ChevronLeft, Send, Sparkle, Star, CheckCircle, 
  RotateCcw, ChevronRight, XCircle, Maximize2, FileSearch
} from 'lucide-react';
import { storageService } from '../services/storageService';
import { geminiService } from '../services/geminiService';
import { Document, ChatMessage, FlashcardSet, Quiz } from '../types';

const DocumentDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [doc, setDoc] = useState<Document | null>(null);
  const [activeTab, setActiveTab] = useState<'content' | 'chat' | 'actions' | 'flashcards' | 'quiz'>('content');
  const [contentView, setContentView] = useState<'pdf' | 'text'>('pdf');
  const [isLoading, setIsLoading] = useState(false);

  // Chat State
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Flashcard State
  const [flashcardSets, setFlashcardSets] = useState<FlashcardSet[]>([]);
  const [currentSetIdx, setCurrentSetIdx] = useState(0);
  const [cardIdx, setCardIdx] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  // Quiz State
  const [activeQuiz, setActiveQuiz] = useState<Quiz | null>(null);
  const [quizStep, setQuizStep] = useState(0);
  const [userAnswers, setUserAnswers] = useState<number[]>([]);
  const [showResults, setShowResults] = useState(false);

  useEffect(() => {
    if (id) {
      const found = storageService.getDocuments().find(d => d.id === id);
      if (found) {
        setDoc(found);
        setMessages(storageService.getChats(id));
        setFlashcardSets(storageService.getFlashcardSets().filter(s => s.documentId === id));
      }
    }
  }, [id]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSendMessage = async () => {
    if (!input.trim() || !doc) return;
    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    storageService.saveChatMessage(doc.id, userMsg);
    setInput('');
    setIsLoading(true);

    try {
      const history = messages.map(m => ({ role: m.role, content: m.content }));
      const response = await geminiService.chatWithDocument(doc.extractedText, history, input);
      const aiMsg: ChatMessage = { role: 'model', content: response || "I couldn't process that.", timestamp: Date.now() };
      setMessages(prev => [...prev, aiMsg]);
      storageService.saveChatMessage(doc.id, aiMsg);
    } finally {
      setIsLoading(false);
    }
  };

  const generateSummary = async () => {
    if (!doc) return;
    setIsLoading(true);
    try {
      const summary = await geminiService.generateSummary(doc.extractedText);
      storageService.updateDocument(doc.id, { summary: summary || "" });
      setDoc(prev => prev ? { ...prev, summary: summary || "" } : null);
    } finally {
      setIsLoading(false);
    }
  };

  const generateFlashcards = async () => {
    if (!doc) return;
    setIsLoading(true);
    try {
      const cards = await geminiService.generateFlashcards(doc.extractedText);
      const newSet: FlashcardSet = {
        id: Math.random().toString(36).substr(2, 9),
        documentId: doc.id,
        title: `Cards from ${doc.title}`,
        cards: cards.map((c: any) => ({
          ...c,
          id: Math.random().toString(36).substr(2, 9),
          isStarred: false,
          isReviewed: false
        })),
        createdAt: Date.now()
      };
      storageService.saveFlashcardSet(newSet);
      setFlashcardSets(prev => [...prev, newSet]);
      alert('Flashcards generated successfully!');
    } finally {
      setIsLoading(false);
    }
  };

  const generateQuiz = async () => {
    if (!doc) return;
    setIsLoading(true);
    try {
      const questions = await geminiService.generateQuiz(doc.extractedText);
      const newQuiz: Quiz = {
        id: Math.random().toString(36).substr(2, 9),
        documentId: doc.id,
        title: `Quiz for ${doc.title}`,
        questions: questions.map((q: any) => ({ ...q, id: Math.random().toString(36).substr(2, 9) }))
      };
      storageService.saveQuiz(newQuiz);
      setActiveQuiz(newQuiz);
      setUserAnswers(new Array(newQuiz.questions.length).fill(-1));
      setQuizStep(0);
      setShowResults(false);
    } finally {
      setIsLoading(false);
    }
  };

  const submitQuiz = () => {
    if (!activeQuiz) return;
    let correct = 0;
    activeQuiz.questions.forEach((q, i) => {
      if (userAnswers[i] === q.correctIndex) correct++;
    });
    const score = Math.round((correct / activeQuiz.questions.length) * 100);
    storageService.updateQuiz(activeQuiz.id, { score, attemptedAt: Date.now() });
    setShowResults(true);
  };

  if (!doc) return <div>Document not found.</div>;

  return (
    <div className="max-w-6xl mx-auto h-full flex flex-col gap-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <Link to="/documents" className="p-2 text-gray-400 hover:bg-gray-100 rounded-lg transition-colors">
            <ChevronLeft size={20} />
          </Link>
          <div>
            <h1 className="text-xl font-bold flex items-center gap-2">
              <FileText className="text-red-500" />
              {doc.title}
            </h1>
            <p className="text-xs text-gray-500 mt-0.5 font-medium">Uploaded {new Date(doc.createdAt).toLocaleDateString()}</p>
          </div>
        </div>
      </div>

      {/* Tabs Nav */}
      <div className="flex items-center border-b border-gray-200 gap-2 overflow-x-auto scrollbar-hide">
        {[
          { id: 'content', icon: FileText, label: 'Content' },
          { id: 'chat', icon: MessageSquare, label: 'Chat' },
          { id: 'actions', icon: Sparkles, label: 'AI Actions' },
          { id: 'flashcards', icon: BookOpen, label: 'Flashcards' },
          { id: 'quiz', icon: Target, label: 'Quiz' },
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex items-center gap-2 px-6 py-3 text-sm font-semibold transition-all border-b-2 whitespace-nowrap ${
              activeTab === tab.id ? 'border-green-600 text-green-600' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
            }`}
          >
            <tab.icon size={18} />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Tab Content */}
      <div className="flex-1 bg-white border border-gray-200 rounded-2xl shadow-sm overflow-hidden relative">
        {isLoading && (
          <div className="absolute inset-0 bg-white/70 backdrop-blur-md z-50 flex flex-col items-center justify-center">
            <div className="w-14 h-14 border-4 border-green-100 border-t-green-600 rounded-full animate-spin mb-4 shadow-sm" />
            <p className="text-green-800 font-bold tracking-tight">AI is processing your document...</p>
          </div>
        )}

        {/* Content Tab */}
        {activeTab === 'content' && (
          <div className="h-full flex flex-col">
            <div className="p-3 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
              <div className="flex items-center gap-2 px-2">
                <FileSearch size={16} className="text-gray-400" />
                <span className="text-xs font-bold text-gray-500 uppercase tracking-widest">Document Viewer</span>
              </div>
              <div className="flex bg-white p-1 rounded-lg border border-gray-200 shadow-sm">
                <button 
                  onClick={() => setContentView('pdf')}
                  className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all ${contentView === 'pdf' ? 'bg-green-600 text-white shadow-sm' : 'text-gray-500 hover:bg-gray-100'}`}
                >
                  PDF
                </button>
                <button 
                  onClick={() => setContentView('text')}
                  className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all ${contentView === 'text' ? 'bg-green-600 text-white shadow-sm' : 'text-gray-500 hover:bg-gray-100'}`}
                >
                  Text
                </button>
              </div>
            </div>

            <div className="flex-1 relative overflow-hidden">
              {contentView === 'pdf' ? (
                <iframe 
                  src={doc.filePath} 
                  className="w-full h-full border-none"
                  title={doc.title}
                />
              ) : (
                <div className="h-full p-8 overflow-y-auto">
                  <div className="max-w-3xl mx-auto space-y-6">
                    <div className="bg-gray-50 p-8 rounded-2xl border border-gray-200 shadow-inner">
                      <h3 className="font-bold mb-6 uppercase text-xs tracking-[0.2em] text-gray-400 border-b border-gray-200 pb-2">EXTRACTED CONTENT</h3>
                      <p className="text-gray-800 leading-[1.8] whitespace-pre-wrap font-medium text-sm">{doc.extractedText}</p>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {/* Chat Tab */}
        {activeTab === 'chat' && (
          <div className="h-full flex flex-col">
            <div className="flex-1 overflow-y-auto p-4 lg:p-6 space-y-4 bg-gray-50">
              {messages.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-center p-8">
                  <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-4 shadow-sm">
                    <MessageSquare size={32} />
                  </div>
                  <h3 className="text-lg font-bold">Ask anything about this document</h3>
                  <p className="text-gray-500 max-w-sm mt-2 font-medium">Our AI assistant is ready to help you understand complex concepts within your document.</p>
                </div>
              )}
              {messages.map((msg, i) => (
                <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-bottom-2`}>
                  <div className={`max-w-[85%] rounded-2xl px-5 py-3.5 shadow-sm ${
                    msg.role === 'user' 
                      ? 'bg-green-600 text-white rounded-br-none shadow-green-100' 
                      : 'bg-white text-gray-800 rounded-bl-none border border-gray-100'
                  }`}>
                    <p className="text-sm leading-relaxed font-medium">{msg.content}</p>
                    <p className={`text-[10px] mt-1.5 font-bold uppercase tracking-wider opacity-60 ${msg.role === 'user' ? 'text-green-100' : 'text-gray-400'}`}>
                      {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </p>
                  </div>
                </div>
              ))}
              <div ref={chatEndRef} />
            </div>
            <div className="p-4 border-t border-gray-200 bg-white flex gap-3">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                placeholder="Ask a question about the content..."
                className="flex-1 bg-gray-100 border-none rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-green-500 transition-all font-medium"
              />
              <button 
                onClick={handleSendMessage}
                disabled={!input.trim() || isLoading}
                className="bg-green-600 text-white p-3 rounded-xl hover:bg-green-700 disabled:bg-gray-300 transition-all shadow-md active:scale-95 flex items-center justify-center"
              >
                <Send size={20} />
              </button>
            </div>
          </div>
        )}

        {/* AI Actions Tab */}
        {activeTab === 'actions' && (
          <div className="h-full p-8 overflow-y-auto">
            <div className="max-w-2xl mx-auto space-y-8">
              <div className="bg-gradient-to-br from-green-50 to-blue-50 p-8 rounded-3xl border border-green-100 flex items-start gap-5 shadow-sm">
                <div className="p-4 bg-white rounded-2xl shadow-sm text-green-600 border border-green-50">
                  <Sparkle size={28} />
                </div>
                <div className="flex-1">
                  <h3 className="font-bold text-xl mb-2">Generate Smart Summary</h3>
                  <p className="text-gray-600 text-sm mb-6 font-medium">Get a structured breakdown of the key concepts and actionable takeaways from this document using Gemini Pro.</p>
                  <button 
                    onClick={generateSummary}
                    disabled={isLoading}
                    className="bg-green-600 text-white px-8 py-3 rounded-xl font-bold text-sm hover:bg-green-700 transition-all shadow-lg active:scale-95 flex items-center gap-2"
                  >
                    {isLoading ? 'Processing...' : 'Summarize Now'}
                    {!isLoading && <Sparkles size={16} />}
                  </button>
                </div>
              </div>

              {doc.summary && (
                <div className="bg-white p-8 rounded-3xl border border-gray-200 shadow-sm animate-in fade-in slide-in-from-bottom-4">
                  <div className="flex items-center gap-2 text-green-600 mb-6 border-b border-gray-100 pb-4">
                    <Sparkles size={20} />
                    <h4 className="font-bold uppercase text-xs tracking-[0.2em]">AI GENERATED SUMMARY</h4>
                  </div>
                  <div className="prose prose-sm max-w-none text-gray-700 leading-[1.8] whitespace-pre-wrap font-medium">
                    {doc.summary}
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {/* Flashcards Tab */}
        {activeTab === 'flashcards' && (
          <div className="h-full p-8 flex flex-col items-center overflow-y-auto">
            {flashcardSets.length === 0 ? (
              <div className="text-center py-12">
                <div className="w-24 h-24 bg-green-50 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6 shadow-sm border border-green-100">
                  <BookOpen size={48} />
                </div>
                <h3 className="text-2xl font-bold mb-3">No study sets created</h3>
                <p className="text-gray-500 mb-8 max-w-sm mx-auto font-medium">Let AI scan your document and create high-quality study cards automatically.</p>
                <button 
                  onClick={generateFlashcards} 
                  disabled={isLoading}
                  className="bg-green-600 text-white px-10 py-4 rounded-2xl font-bold hover:bg-green-700 shadow-xl active:scale-95 transition-all flex items-center gap-2 mx-auto"
                >
