                    className={`w-14 h-14 flex items-center justify-center rounded-full shadow-md transition-all hover:scale-105 active:scale-95 ${
                      flashcardSets[currentSetIdx].cards[cardIdx].isStarred ? 'bg-yellow-400 text-white border-none' : 'bg-white border border-gray-100 text-gray-400'
                    }`}
                  >
                    <Star size={24} fill={flashcardSets[currentSetIdx].cards[cardIdx].isStarred ? 'currentColor' : 'none'} />
                  </button>
                  <button 
                    disabled={cardIdx === flashcardSets[currentSetIdx].cards.length - 1}
                    onClick={() => { setCardIdx(cardIdx + 1); setIsFlipped(false); }}
                    className="w-14 h-14 flex items-center justify-center bg-green-600 text-white rounded-full shadow-md shadow-green-100 disabled:bg-gray-200 hover:bg-green-700 transition-all hover:scale-105 active:scale-95"
