            {!activeQuiz ? (
              <div className="max-w-md mx-auto text-center py-12">
                <div className="w-24 h-24 bg-purple-50 text-purple-600 rounded-full flex items-center justify-center mx-auto mb-6 shadow-sm border border-purple-100">
                  <Target size={48} />
                </div>
                <h3 className="text-2xl font-bold mb-3">Ready for a challenge?</h3>
                <p className="text-gray-500 mb-10 font-medium">Test your mastery with an AI-curated multiple-choice quiz derived specifically from this document's core concepts.</p>
                <div className="grid grid-cols-2 gap-4 mb-10">
                  <div className="p-5 border border-gray-100 rounded-2xl bg-gray-50/50 shadow-inner">
                    <span className="block text-3xl font-black text-gray-900">5</span>
                    <span className="text-[10px] text-gray-400 uppercase font-black tracking-widest">Questions</span>
                  </div>
                  <div className="p-5 border border-gray-100 rounded-2xl bg-gray-50/50 shadow-inner">
                    <span className="block text-3xl font-black text-gray-900">MCQ</span>
                    <span className="text-[10px] text-gray-400 uppercase font-black tracking-widest">Adaptive</span>
                  </div>
                </div>
                <button 
                  onClick={generateQuiz} 
                  disabled={isLoading}
                  className="w-full bg-green-600 text-white py-4.5 rounded-2xl font-bold shadow-xl shadow-green-100 hover:bg-green-700 transition-all active:scale-95 flex items-center justify-center gap-2"
                >
                  Start Assessment Now
                  <ChevronRight size={18} />
                </button>
              </div>
            ) : showResults ? (
              <div className="max-w-2xl mx-auto space-y-8 animate-in zoom-in-95 duration-500">
                <div className="text-center p-10 bg-green-50 rounded-[2.5rem] border border-green-100 shadow-sm">
                  <div className="w-24 h-24 bg-green-600 text-white rounded-full flex items-center justify-center text-3xl font-black mx-auto mb-6 shadow-2xl ring-4 ring-white">
                    {activeQuiz.score}%
                  </div>
                  <h2 className="text-3xl font-bold text-green-900 mb-2">Quiz Completed!</h2>
                  <p className="text-green-700 font-medium max-w-sm mx-auto">Great job! You have demonstrated significant understanding of the material.</p>
                </div>

                <div className="space-y-6 pt-4">
                  <h3 className="font-bold text-gray-900 border-b border-gray-100 pb-3 flex items-center gap-2">
                    <Sparkle size={18} className="text-green-600" />
                    DETAILED REVIEW
                  </h3>
                  {activeQuiz.questions.map((q, i) => (
                    <div key={q.id} className={`p-8 rounded-[2rem] border-2 transition-all ${userAnswers[i] === q.correctIndex ? 'bg-white border-green-100 shadow-sm' : 'bg-red-50 border-red-100'}`}>
                      <div className="flex items-start gap-6">
                        <div className={`w-10 h-10 rounded-2xl flex items-center justify-center flex-shrink-0 font-black shadow-sm ${
                          userAnswers[i] === q.correctIndex ? 'bg-green-600 text-white' : 'bg-red-500 text-white'
                        }`}>
                          {i + 1}
                        </div>
                        <div className="flex-1">
                          <p className="font-bold text-gray-900 text-lg mb-6 leading-snug">{q.question}</p>
                          <div className="grid gap-3 mb-6">
                            {q.options.map((opt, optIdx) => (
                              <div key={optIdx} className={`p-4 rounded-xl text-sm border-2 flex items-center justify-between transition-all ${
                                optIdx === q.correctIndex ? 'bg-green-100 border-green-200 text-green-900 font-bold' :
                                optIdx === userAnswers[i] ? 'bg-red-100 border-red-200 text-red-900 font-bold' : 'bg-white border-gray-100 text-gray-500'
                              }`}>
                                {opt}
                                {optIdx === q.correctIndex && <CheckCircle size={18} className="text-green-600" />}
                                {optIdx === userAnswers[i] && optIdx !== q.correctIndex && <XCircle size={18} className="text-red-600" />}
                              </div>
                            ))}
                          </div>
                          <div className="p-5 bg-gray-50 rounded-2xl border border-gray-100 text-sm text-gray-700 leading-relaxed shadow-inner">
                            <span className="font-black block mb-2 text-xs text-gray-400 uppercase tracking-widest">EXPLANATION</span>
                            {q.explanation}
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="flex gap-4 pb-16">
                  <button 
                    onClick={() => { setActiveQuiz(null); setQuizStep(0); setShowResults(false); }} 
                    className="flex-1 flex items-center justify-center gap-3 bg-white border-2 border-gray-100 py-4 rounded-2xl font-bold text-gray-700 hover:bg-gray-50 transition-all hover:border-gray-200 active:scale-95 shadow-sm"
                  >
                    <RotateCcw size={20} /> RETAKE ASSESSMENT
                  </button>
                </div>
              </div>
            ) : (
              <div className="max-w-xl mx-auto space-y-10 animate-in slide-in-from-right-4 duration-500">
                <div className="space-y-4">
                  <div className="flex items-center justify-between px-1">
                    <span className="text-xs font-black text-green-600 uppercase tracking-[0.3em]">QUESTION {quizStep + 1} OF {activeQuiz.questions.length}</span>
                    <span className="text-xs font-bold text-gray-400">Progess: {Math.round(((quizStep) / activeQuiz.questions.length) * 100)}%</span>
                  </div>
                  <div className="w-full h-3 bg-gray-100 rounded-full overflow-hidden shadow-inner border border-gray-50">
                    <div className="h-full bg-green-500 transition-all duration-700 ease-out shadow-sm" style={{ width: `${((quizStep + 1) / activeQuiz.questions.length) * 100}%` }}></div>
                  </div>
                </div>

                <div className="space-y-8 bg-white p-2 rounded-3xl">
                  <h2 className="text-2xl font-black text-gray-900 leading-snug">{activeQuiz.questions[quizStep].question}</h2>
                  <div className="grid gap-4">
                    {activeQuiz.questions[quizStep].options.map((option, idx) => (
                      <button
                        key={idx}
                        onClick={() => {
                          const updated = [...userAnswers];
                          updated[quizStep] = idx;
                          setUserAnswers(updated);
                        }}
                        className={`w-full text-left p-5 rounded-2xl border-2 transition-all group flex items-center justify-between shadow-sm ${
                          userAnswers[quizStep] === idx ? 'border-green-600 bg-green-50/50 shadow-green-50 ring-4 ring-green-100/50' : 'border-gray-100 hover:border-green-200 hover:bg-gray-50 hover:shadow-md'
                        }`}
                      >
                        <span className={`text-base font-bold transition-colors ${userAnswers[quizStep] === idx ? 'text-green-900' : 'text-gray-700 group-hover:text-gray-900'}`}>{option}</span>
                        <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all ${userAnswers[quizStep] === idx ? 'border-green-600 bg-green-600 scale-110 shadow-sm' : 'border-gray-200 bg-white group-hover:border-green-300'}`}>
                          {userAnswers[quizStep] === idx && <div className="w-2 h-2 rounded-full bg-white shadow-inner animate-in zoom-in-50"></div>}
                        </div>
                      </button>
                    ))}
                  </div>
                </div>

                <div className="flex items-center justify-between pt-6 border-t border-gray-100">
                  <button 
                    disabled={quizStep === 0}
                    onClick={() => setQuizStep(quizStep - 1)}
                    className="px-8 py-3 text-gray-400 font-black text-xs uppercase tracking-widest disabled:opacity-30 hover:text-gray-900 transition-colors flex items-center gap-2"
                  >
                    <ChevronLeft size={16} /> BACK
                  </button>
                  {quizStep === activeQuiz.questions.length - 1 ? (
                    <button 
                      onClick={submitQuiz}
                      disabled={userAnswers[quizStep] === -1}
                      className="bg-green-600 text-white px-12 py-4 rounded-2xl font-black text-sm shadow-xl shadow-green-100 hover:bg-green-700 transition-all disabled:bg-gray-200 active:scale-95 flex items-center gap-2 uppercase tracking-widest"
                    >
                      COMPLETE QUIZ
                      <CheckCircle size={18} />
                    </button>
                  ) : (
                    <button 
                      onClick={() => setQuizStep(quizStep + 1)}
                      disabled={userAnswers[quizStep] === -1}
                      className="bg-green-600 text-white px-12 py-4 rounded-2xl font-black text-sm shadow-xl shadow-green-100 hover:bg-green-700 transition-all disabled:bg-gray-200 active:scale-95 flex items-center gap-2 uppercase tracking-widest"
                    >
                      NEXT
                      <ChevronRight size={18} />
                    </button>
                  )}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default DocumentDetail;

import React, { useState, useRef } from 'react';
import { Plus, FileText, Search, MoreVertical, ExternalLink, Trash2, Clock } from 'lucide-react';
import { storageService } from '../services/storageService';
import { Document } from '../types';
import { Link } from 'react-router-dom';

const Documents: React.FC = () => {
  const [docs, setDocs] = useState<Document[]>(storageService.getDocuments());
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const readFileAsBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || file.type !== 'application/pdf') {
      alert('Please upload a valid PDF file.');
      return;
    }

    if (file.size > 5 * 1024 * 1024) {
      alert('File is too large for local storage. Please use a PDF under 5MB.');
      return;
    }

    setIsUploading(true);

    try {
      const base64Data = await readFileAsBase64(file);

      // Simulate reading PDF text
      // In a real app, this would happen on the server via a library like pdf-parse
      const newDoc: Document = {
        id: Math.random().toString(36).substr(2, 9),
        userId: '1',
        title: file.name.replace('.pdf', ''),
        filePath: base64Data,
        extractedText: `Simulated extracted text for ${file.name}. 

This document covers essential topics in advanced mathematics and computer science. 
It explores the foundations of algorithms, data structures, and the mathematical principles that govern computational efficiency. 
Key concepts include Big O notation, complexity classes (P vs NP), and the implementation of binary search trees and hash maps. 
Furthermore, it discusses practical applications in modern software engineering, focusing on scalability and robust system design.`,
        createdAt: Date.now()
      };

      storageService.saveDocument(newDoc);
      setDocs(prev => [...prev, newDoc]);
    } catch (error) {
      console.error("Upload failed", error);
      alert("Failed to process the document.");
    } finally {
      setIsUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const deleteDoc = (id: string) => {
    if (confirm('Are you sure you want to delete this document?')) {
      const updated = docs.filter(d => d.id !== id);
      localStorage.setItem('ai_learn_docs', JSON.stringify(updated));
      setDocs(updated);
    }
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold">My Documents</h1>
          <p className="text-gray-500">Upload and manage your study materials.</p>
        </div>
        <button 
          onClick={() => fileInputRef.current?.click()}
          disabled={isUploading}
          className="bg-green-600 hover:bg-green-700 disabled:bg-gray-400 text-white px-4 py-2 rounded-lg font-medium flex items-center justify-center gap-2 transition-colors shadow-sm active:scale-95"
        >
          {isUploading ? (
            <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
          ) : (
            <Plus size={20} />
          )}
          {isUploading ? 'Processing...' : 'Upload PDF'}
        </button>
        <input 
          type="file" 
          ref={fileInputRef} 
          className="hidden" 
          accept=".pdf" 
          onChange={handleFileUpload} 
        />
      </div>

      <div className="bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">
        <div className="p-4 border-b border-gray-100 bg-gray-50/50 flex items-center gap-3">
          <Search size={18} className="text-gray-400" />
          <input 
            type="text" 
            placeholder="Search your documents..." 
            className="bg-transparent border-none outline-none text-sm w-full font-medium"
          />
        </div>

        <div className="divide-y divide-gray-100">
          {docs.length > 0 ? docs.map((doc) => (
            <div key={doc.id} className="p-4 hover:bg-gray-50 transition-colors flex items-center justify-between group">
              <div className="flex items-center gap-4 min-w-0">
                <div className="w-12 h-12 bg-red-50 text-red-500 rounded-lg flex items-center justify-center flex-shrink-0 border border-red-100">
                  <FileText size={24} />
                </div>
                <div className="min-w-0">
                  <h3 className="font-semibold text-gray-900 truncate">{doc.title}</h3>
                  <div className="flex items-center gap-3 text-xs text-gray-500 mt-1 font-medium">
                    <span className="flex items-center gap-1">
                      <Clock size={12} /> {new Date(doc.createdAt).toLocaleDateString()}
                    </span>
                    <span className="bg-gray-100 px-1.5 py-0.5 rounded text-[10px] uppercase font-bold tracking-wider">PDF</span>
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <Link 
                  to={`/documents/${doc.id}`}
                  className="p-2 text-gray-400 hover:text-green-600 hover:bg-green-50 rounded-lg transition-all"
                  title="Open Study Space"
                >
                  <ExternalLink size={20} />
                </Link>
                <button 
                  onClick={() => deleteDoc(doc.id)}
                  className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                  title="Delete Document"
                >
                  <Trash2 size={20} />
                </button>
              </div>
            </div>
          )) : (
            <div className="p-12 text-center text-gray-500 bg-gray-50/20">
              <FileText size={48} className="mx-auto mb-4 text-gray-200" />
              <p className="font-medium">No documents found.</p>
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="text-green-600 font-bold hover:underline mt-2 text-sm"
              >
                Start by uploading a PDF (max 5MB)
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

