import React, { useState, useEffect, useRef } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
  FileText, MessageSquare, Sparkles, BookOpen, Target, 
  ChevronLeft, Send, Sparkle, Star, CheckCircle, 
  RotateCcw, ChevronRight, XCircle, FileSearch, Download, AlertCircle
} from 'lucide-react';
import { storageService } from '../services/storageService';
import { geminiService } from '../services/geminiService';
import { Document, ChatMessage, FlashcardSet, Quiz } from '../types';

const DocumentDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [doc, setDoc] = useState<Document | null>(null);
  const [activeTab, setActiveTab] = useState<'content' | 'chat' | 'actions' | 'flashcards' | 'quiz'>('content');
  const [contentView, setContentView] = useState<'pdf' | 'text'>('pdf');
  const [isLoading, setIsLoading] = useState(false);

  // Chat State
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Flashcard State
  const [flashcardSets, setFlashcardSets] = useState<FlashcardSet[]>([]);
  const [currentSetIdx, setCurrentSetIdx] = useState(0);
  const [cardIdx, setCardIdx] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  // Quiz State
  const [activeQuiz, setActiveQuiz] = useState<Quiz | null>(null);
  const [quizStep, setQuizStep] = useState(0);
  const [userAnswers, setUserAnswers] = useState<number[]>([]);
  const [showResults, setShowResults] = useState(false);

  useEffect(() => {
    if (id) {
      const found = storageService.getDocuments().find(d => d.id === id);
      if (found) {
        setDoc(found);
        setMessages(storageService.getChats(id));
        setFlashcardSets(storageService.getFlashcardSets().filter(s => s.documentId === id));
      }
    }
  }, [id]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSendMessage = async () => {
    if (!input.trim() || !doc) return;
    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    storageService.saveChatMessage(doc.id, userMsg);
    setInput('');
    setIsLoading(true);

    try {
      const history = messages.map(m => ({ role: m.role, content: m.content }));
      const response = await geminiService.chatWithDocument(doc.extractedText, history, input);
      const aiMsg: ChatMessage = { role: 'model', content: response || "I couldn't process that.", timestamp: Date.now() };
      setMessages(prev => [...prev, aiMsg]);
      storageService.saveChatMessage(doc.id, aiMsg);
    } finally {
      setIsLoading(false);
    }
  };

  const generateSummary = async () => {
    if (!doc) return;
    setIsLoading(true);
    try {
      const summary = await geminiService.generateSummary(doc.extractedText);
      storageService.updateDocument(doc.id, { summary: summary || "" });
      setDoc(prev => prev ? { ...prev, summary: summary || "" } : null);
    } finally {
      setIsLoading(false);
    }
  };

  const generateFlashcards = async () => {
    if (!doc) return;
    setIsLoading(true);
    try {
      const cards = await geminiService.generateFlashcards(doc.extractedText);
      const newSet: FlashcardSet = {
        id: Math.random().toString(36).substr(2, 9),
        documentId: doc.id,
        title: `Cards from ${doc.title}`,
        cards: cards.map((c: any) => ({
          ...c,
          id: Math.random().toString(36).substr(2, 9),
          isStarred: false,
          isReviewed: false
        })),
        createdAt: Date.now()
      };
      storageService.saveFlashcardSet(newSet);
      setFlashcardSets(prev => [...prev, newSet]);
      alert('Flashcards generated successfully!');
    } finally {
      setIsLoading(false);
    }
  };

  const generateQuiz = async () => {
    if (!doc) return;
    setIsLoading(true);
    try {
      const questions = await geminiService.generateQuiz(doc.extractedText);
      const newQuiz: Quiz = {
        id: Math.random().toString(36).substr(2, 9),
        documentId: doc.id,
        title: `Quiz for ${doc.title}`,
        questions: questions.map((q: any) => ({ ...q, id: Math.random().toString(36).substr(2, 9) }))
      };
      storageService.saveQuiz(newQuiz);
      setActiveQuiz(newQuiz);
      setUserAnswers(new Array(newQuiz.questions.length).fill(-1));
      setQuizStep(0);
      setShowResults(false);
    } finally {
      setIsLoading(false);
    }
  };

  const submitQuiz = () => {
    if (!activeQuiz) return;
    let correct = 0;
    activeQuiz.questions.forEach((q, i) => {
      if (userAnswers[i] === q.correctIndex) correct++;
    });
    const score = Math.round((correct / activeQuiz.questions.length) * 100);
    storageService.updateQuiz(activeQuiz.id, { score, attemptedAt: Date.now() });
    setShowResults(true);
  };

  if (!doc) return <div>Document not found.</div>;

  return (
    <div className="max-w-6xl mx-auto h-full flex flex-col gap-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <Link to="/documents" className="p-2 text-gray-400 hover:bg-gray-100 rounded-lg transition-colors">
            <ChevronLeft size={20} />
          </Link>
          <div>
            <h1 className="text-xl font-bold flex items-center gap-2">
              <FileText className="text-red-500" />
              {doc.title}
            </h1>
            <p className="text-xs text-gray-500 mt-0.5 font-medium">Uploaded {new Date(doc.createdAt).toLocaleDateString()}</p>
          </div>
        </div>
      </div>

      {/* Tabs Nav */}
      <div className="flex items-center border-b border-gray-200 gap-2 overflow-x-auto scrollbar-hide">
        {[
          { id: 'content', icon: FileText, label: 'Content' },
          { id: 'chat', icon: MessageSquare, label: 'Chat' },
          { id: 'actions', icon: Sparkles, label: 'AI Actions' },
          { id: 'flashcards', icon: BookOpen, label: 'Flashcards' },
          { id: 'quiz', icon: Target, label: 'Quiz' },
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={`flex items-center gap-2 px-6 py-3 text-sm font-semibold transition-all border-b-2 whitespace-nowrap ${
              activeTab === tab.id ? 'border-green-600 text-green-600' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
            }`}
          >
            <tab.icon size={18} />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Tab Content */}
      <div className="flex-1 bg-white border border-gray-200 rounded-2xl shadow-sm overflow-hidden relative">
        {isLoading && (
          <div className="absolute inset-0 bg-white/70 backdrop-blur-md z-50 flex flex-col items-center justify-center">
            <div className="w-14 h-14 border-4 border-green-100 border-t-green-600 rounded-full animate-spin mb-4 shadow-sm" />
            <p className="text-green-800 font-bold tracking-tight">AI is processing your document...</p>
          </div>
        )}

        {/* Content Tab */}
        {activeTab === 'content' && (
          <div className="h-full flex flex-col">
            <div className="p-3 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
              <div className="flex items-center gap-2 px-2">
                <FileSearch size={16} className="text-gray-400" />
                <span className="text-xs font-bold text-gray-500 uppercase tracking-widest">Document Viewer</span>
              </div>
              <div className="flex bg-white p-1 rounded-lg border border-gray-200 shadow-sm">
                <button 
                  onClick={() => setContentView('pdf')}
                  className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all ${contentView === 'pdf' ? 'bg-green-600 text-white shadow-sm' : 'text-gray-500 hover:bg-gray-100'}`}
                >
                  PDF
                </button>
                <button 
                  onClick={() => setContentView('text')}
                  className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all ${contentView === 'text' ? 'bg-green-600 text-white shadow-sm' : 'text-gray-500 hover:bg-gray-100'}`}
                >
                  Text
                </button>
              </div>
            </div>

            <div className="flex-1 relative overflow-hidden bg-gray-100">
              {contentView === 'pdf' ? (
                <div className="w-full h-full flex items-center justify-center">
                  <object
                    data={doc.filePath}
                    type="application/pdf"
                    className="w-full h-full"
                  >
                    <div className="p-8 text-center max-w-sm">
                      <AlertCircle size={48} className="mx-auto text-gray-300 mb-4" />
                      <h3 className="text-lg font-bold mb-2">Unable to display PDF</h3>
                      <p className="text-sm text-gray-500 mb-6">Your browser might be blocking the inline PDF view. You can download the file to view it locally.</p>
                      <a 
                        href={doc.filePath} 
                        download={`${doc.title}.pdf`}
                        className="inline-flex items-center gap-2 bg-green-600 text-white px-6 py-2 rounded-xl font-bold shadow-md hover:bg-green-700"
                      >
                        <Download size={18} /> Download PDF
                      </a>
                    </div>
                  </object>
                </div>
              ) : (
                <div className="h-full p-8 overflow-y-auto bg-white">
                  <div className="max-w-3xl mx-auto space-y-6">
                    <div className="bg-gray-50 p-8 rounded-2xl border border-gray-200 shadow-inner">
                      <h3 className="font-bold mb-6 uppercase text-xs tracking-[0.2em] text-gray-400 border-b border-gray-200 pb-2">EXTRACTED CONTENT</h3>
