                      <p className="text-lg lg:text-xl font-semibold leading-relaxed">{flashcardSets[currentSetIdx].cards[cardIdx].answer}</p>
                      <div className="mt-auto flex items-center gap-2 text-[10px] font-bold text-green-100 uppercase tracking-widest bg-green-700/50 px-4 py-2 rounded-full">
                        <RotateCcw size={12} /> Click to reveal question
                      </div>
                    </div>
                  </div>
                </div>

                <div className="flex items-center justify-center gap-8">
                  <button 
                    disabled={cardIdx === 0}
                    onClick={() => { setCardIdx(cardIdx - 1); setIsFlipped(false); }}
                    className="w-14 h-14 flex items-center justify-center bg-white border border-gray-100 text-gray-600 rounded-full shadow-md disabled:opacity-30 hover:bg-gray-50 transition-all hover:scale-105 active:scale-95"
                  >
                    <ChevronLeft size={24} />
                  </button>
                  <button 
                    onClick={() => {
                      const updated = [...flashcardSets];
                      updated[currentSetIdx].cards[cardIdx].isStarred = !updated[currentSetIdx].cards[cardIdx].isStarred;
                      setFlashcardSets(updated);
                      storageService.updateFlashcardSet(updated[currentSetIdx].id, { cards: updated[currentSetIdx].cards });
                    }}
                    className={`w-14 h-14 flex items-center justify-center rounded-full shadow-md transition-all hover:scale-105 active:scale-95 ${
                      flashcardSets[currentSetIdx].cards[cardIdx].isStarred ? 'bg-yellow-400 text-white border-none' : 'bg-white border border-gray-100 text-gray-400'
