        {/* AI Actions Tab */}
        {activeTab === 'actions' && (
          <div className="h-full p-12 overflow-y-auto">
            <div className="max-w-4xl mx-auto space-y-12">
              <div className="bg-gradient-to-br from-green-500 to-green-700 p-12 rounded-[3rem] text-white flex flex-col md:flex-row items-center gap-10 shadow-2xl shadow-green-200">
