import React, { useState, useEffect, createContext, useContext } from 'react';
import { Routes, Route, Navigate, useNavigate, useLocation, Link } from 'react-router-dom';
import { LayoutDashboard, FileText, BookOpen, User as UserIcon, LogOut, Bell, Menu, X, Plus, ChevronRight, Search } from 'lucide-react';
import { User } from './types';
import { storageService } from './services/storageService';

// Pages
import Dashboard from './pages/Dashboard';
import Documents from './pages/Documents';
import DocumentDetail from './pages/DocumentDetail';
import GlobalFlashcards from './pages/GlobalFlashcards';
import Profile from './pages/Profile';
import Auth from './pages/Auth';

// Auth Context
interface AuthContextType {
  user: User | null;
  login: (email: string, name?: string) => void;
  logout: () => void;
  updateUser: (updates: Partial<User>) => void;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error("useAuth must be used within AuthProvider");
  return context;
};

const SidebarItem = ({ to, icon: Icon, label, active }: { to: string, icon: any, label: string, active: boolean }) => (
  <Link
    to={to}
    className={`flex items-center gap-3 px-6 py-4 rounded-2xl transition-all ${
      active ? 'bg-green-600 text-white shadow-lg shadow-green-100 font-bold' : 'text-gray-500 hover:bg-gray-100 hover:text-gray-900 font-semibold'
    }`}
  >
    <Icon size={22} />
    <span className="text-base">{label}</span>
  </Link>
);

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(storageService.getUser());
  const [isLoading, setIsLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();

  const login = (email: string, name?: string) => {
    // If name is provided, it's a new registration. Otherwise, use a default or keep existing.
    const displayName = name || (user?.email === email ? user.name : 'Returning Learner');
    const newUser = { 
      id: Math.random().toString(36).substr(2, 9), 
      name: displayName, 
      email, 
      avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(displayName)}&background=random` 
    };
    setUser(newUser);
    storageService.setUser(newUser);
    navigate('/');
  };

  const logout = () => {
    setUser(null);
    storageService.setUser(null);
    navigate('/auth');
  };

  const updateUser = (updates: Partial<User>) => {
    if (!user) return;
    const updatedUser = { ...user, ...updates };
    setUser(updatedUser);
    storageService.setUser(updatedUser);
  };

  if (!user && location.pathname !== '/auth') {
    return <Navigate to="/auth" />;
  }

  if (location.pathname === '/auth') {
    return <Auth onLogin={login} />;
  }

  return (
    <AuthContext.Provider value={{ user, login, logout, updateUser, isLoading }}>
      <div className="flex h-screen bg-gray-50 overflow-hidden font-['Inter']">
        {/* Mobile Sidebar Overlay */}
        {sidebarOpen && (
          <div 
            className="fixed inset-0 bg-black/60 z-[60] lg:hidden backdrop-blur-sm transition-all"
            onClick={() => setSidebarOpen(false)}
          />
        )}

        {/* Sidebar */}
        <aside className={`
          fixed inset-y-0 left-0 z-[70] w-80 bg-white border-r border-gray-100 transform transition-transform duration-300 ease-out lg:translate-x-0 lg:static lg:inset-0 shadow-2xl lg:shadow-none
          ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        `}>
          <div className="flex flex-col h-full p-6">
            <div className="px-4 py-8 flex items-center justify-between mb-10">
              <div className="flex items-center gap-4 font-black text-3xl text-green-600 tracking-tighter">
                <div className="bg-green-600 text-white p-2.5 rounded-xl shadow-lg shadow-green-100">
                  <BookOpen size={32} />
                </div>
                <span>EduAI</span>
              </div>
              <button className="lg:hidden p-2 text-gray-400" onClick={() => setSidebarOpen(false)}>
                <X size={24} />
              </button>
            </div>

            <nav className="flex-1 space-y-3">
              <SidebarItem to="/" icon={LayoutDashboard} label="Dashboard" active={location.pathname === '/'} />
              <SidebarItem to="/documents" icon={FileText} label="Library" active={location.pathname.startsWith('/documents')} />
              <SidebarItem to="/flashcards" icon={BookOpen} label="Study Sets" active={location.pathname === '/flashcards'} />
              <SidebarItem to="/profile" icon={UserIcon} label="Profile" active={location.pathname === '/profile'} />
            </nav>

            <div className="mt-auto pt-6 border-t border-gray-100">
              <button 
                onClick={logout}
                className="flex items-center gap-4 w-full px-6 py-4 text-gray-400 hover:bg-red-50 hover:text-red-600 rounded-2xl transition-all font-bold"
              >
                <LogOut size={22} />
                <span>Sign Out</span>
              </button>
            </div>
          </div>
        </aside>

        {/* Main Content */}
        <main className="flex-1 flex flex-col min-w-0 overflow-hidden relative">
          {/* Top Navbar */}
          <header className="h-24 bg-white border-b border-gray-100 flex items-center justify-between px-8 lg:px-12 z-40 shrink-0">
            <button className="lg:hidden p-3 text-gray-500 hover:bg-gray-100 rounded-2xl" onClick={() => setSidebarOpen(true)}>
              <Menu size={28} />
            </button>

            <div className="hidden md:flex items-center bg-gray-50 px-6 py-3.5 rounded-2xl border border-gray-100 w-[500px] focus-within:ring-4 focus-within:ring-green-50 focus-within:bg-white transition-all">
              <Search size={22} className="text-gray-400" />
              <input 
                type="text" 
                placeholder="Search across your library..." 
                className="bg-transparent border-none outline-none text-base px-3 w-full font-medium"
              />
            </div>

            <div className="flex items-center gap-6">
              <button className="p-3 text-gray-400 hover:bg-gray-50 hover:text-green-600 rounded-2xl relative transition-all">
                <Bell size={24} />
                <span className="absolute top-2.5 right-2.5 w-2.5 h-2.5 bg-green-500 rounded-full border-2 border-white"></span>
              </button>

              <div className="flex items-center gap-4 pl-6 border-l border-gray-100">
                <div className="text-right hidden sm:block">
                  <p className="text-base font-black text-gray-900 leading-tight">{user?.name}</p>
                  <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mt-0.5">Pro Student</p>
                </div>
                <img 
                  src={user?.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(user?.name || 'User')}&background=random`} 
                  alt="Avatar" 
                  className="w-14 h-14 rounded-[1.25rem] border-2 border-green-50 object-cover shadow-md ring-2 ring-white"
                />
              </div>
            </div>
          </header>

          {/* Page Content */}
          <div className="flex-1 overflow-y-auto p-8 lg:p-12 scroll-smooth custom-scrollbar">
            <Routes>
              <Route path="/" element={<Dashboard />} />
              <Route path="/documents" element={<Documents />} />
              <Route path="/documents/:id" element={<DocumentDetail />} />
              <Route path="/flashcards" element={<GlobalFlashcards />} />
              <Route path="/profile" element={<Profile />} />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          </div>
        </main>
      </div>
    </AuthContext.Provider>
  );
};

export default App;

import React, { useMemo } from 'react';
import { FileText, BookOpen, Target, Clock, ArrowUpRight } from 'lucide-react';
import { storageService } from '../services/storageService';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const Dashboard: React.FC = () => {
  const docs = storageService.getDocuments();
  const sets = storageService.getFlashcardSets();
  const quizzes = storageService.getQuizzes().filter(q => q.score !== undefined);
  const activities = storageService.getActivities();

  const stats = [
    { label: 'Documents', value: docs.length, icon: FileText, color: 'text-blue-600', bg: 'bg-blue-100' },
    { label: 'Flashcard Sets', value: sets.length, icon: BookOpen, color: 'text-green-600', bg: 'bg-green-100' },
    { label: 'Quizzes Taken', value: quizzes.length, icon: Target, color: 'text-purple-600', bg: 'bg-purple-100' },
    { label: 'Avg Score', value: quizzes.length ? `${Math.round(quizzes.reduce((a, b) => a + (b.score || 0), 0) / quizzes.length)}%` : '0%', icon: Clock, color: 'text-orange-600', bg: 'bg-orange-100' },
  ];

  // Generate real chart data from activities
  const chartData = useMemo(() => {
    const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    const now = new Date();

    // Initialize last 7 days with 0
    const dataMap: Record<string, number> = {};
    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setDate(now.getDate() - i);
      dataMap[days[d.getDay()]] = 0;
    }

    // Fill with actual activity counts
    activities.forEach(activity => {
      const activityDate = new Date(activity.timestamp);
      const dayName = days[activityDate.getDay()];
      if (dataMap[dayName] !== undefined) {
        dataMap[dayName]++;
      }
    });

    return Object.entries(dataMap).map(([name, count]) => ({ name, count }));
  }, [activities]);

  return (
    <div className="w-full max-w-[1600px] mx-auto space-y-8 animate-in fade-in duration-500">
      <div>
        <h1 className="text-3xl font-bold tracking-tight text-gray-900">Performance Dashboard</h1>
        <p className="text-gray-500 mt-1 font-medium">Real-time analysis of your academic engagement and mastery.</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-[2rem] border border-gray-100 shadow-sm flex items-center gap-5 hover:shadow-xl hover:-translate-y-1 transition-all duration-300">
            <div className={`${stat.bg} ${stat.color} p-4 rounded-2xl shadow-inner`}>
              <stat.icon size={28} />
            </div>
            <div>
              <p className="text-xs font-black text-gray-400 uppercase tracking-widest">{stat.label}</p>
              <p className="text-3xl font-black text-gray-900 mt-0.5">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Progress Chart */}
        <div className="lg:col-span-2 bg-white p-8 lg:p-10 rounded-[2.5rem] border border-gray-100 shadow-sm flex flex-col">
          <div className="flex items-center justify-between mb-10">
            <div>
              <h2 className="text-xl font-black text-gray-900">Study Intensity</h2>
              <p className="text-sm text-gray-400 font-medium">Activity frequency across the current week</p>
            </div>
            <select className="text-xs font-black uppercase tracking-widest border-2 border-gray-50 bg-gray-50 rounded-xl px-4 py-2 outline-none hover:bg-white hover:border-green-100 transition-all cursor-pointer">
              <option>Current Week</option>
              <option>Last 30 Days</option>
            </select>
          </div>

          <div className="flex-1 w-full min-h-[350px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="8 8" vertical={false} stroke="#f8fafc" />
