import React, { useState, useEffect, createContext, useContext } from 'react';
import { Routes, Route, Navigate, useNavigate, useLocation, Link } from 'react-router-dom';
import { LayoutDashboard, FileText, BookOpen, User as UserIcon, LogOut, Bell, Menu, X, Plus, ChevronRight, Search, Users } from 'lucide-react';
import { User } from './types';
import { storageService } from './services/storageService';

// Pages
import Dashboard from './pages/Dashboard';
import Documents from './pages/Documents';
import DocumentDetail from './pages/DocumentDetail';
import GlobalFlashcards from './pages/GlobalFlashcards';
import Profile from './pages/Profile';
import Auth from './pages/Auth';
import CommunityChat from './pages/CommunityChat';

// Auth Context
interface AuthContextType {
  user: User | null;
  login: (email: string, name?: string) => void;
  logout: () => void;
  updateUser: (updates: Partial<User>) => void;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error("useAuth must be used within AuthProvider");
  return context;
};

const SidebarItem = ({ to, icon: Icon, label, active }: { to: string, icon: any, label: string, active: boolean }) => (
  <Link
    to={to}
    className={`flex items-center gap-3 px-6 py-4 rounded-2xl transition-all ${
      active ? 'bg-green-600 text-white shadow-lg shadow-green-100 font-bold' : 'text-gray-500 hover:bg-gray-100 hover:text-gray-900 font-semibold'
    }`}
  >
    <Icon size={22} />
    <span className="text-base">{label}</span>
  </Link>
);

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(storageService.getUser());
  const [isLoading, setIsLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();

  const login = (email: string, name?: string) => {
    const displayName = name || (user?.email === email ? user.name : 'Returning Learner');
    const newUser = { 
      id: Math.random().toString(36).substr(2, 9), 
      name: displayName, 
      email, 
      avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(displayName)}&background=random` 
    };
    setUser(newUser);
    storageService.setUser(newUser);
    navigate('/');
  };

  const logout = () => {
    setUser(null);
    storageService.setUser(null);
    navigate('/auth');
  };

  const updateUser = (updates: Partial<User>) => {
    if (!user) return;
    const updatedUser = { ...user, ...updates };
    setUser(updatedUser);
    storageService.setUser(updatedUser);
  };

  if (!user && location.pathname !== '/auth') {
    return <Navigate to="/auth" />;
  }

  if (location.pathname === '/auth') {
    return <Auth onLogin={login} />;
  }

  return (
    <AuthContext.Provider value={{ user, login, logout, updateUser, isLoading }}>
      <div className="flex h-screen bg-gray-50 overflow-hidden font-['Inter']">
        {/* Mobile Sidebar Overlay */}
        {sidebarOpen && (
          <div 
            className="fixed inset-0 bg-black/60 z-[60] lg:hidden backdrop-blur-sm transition-all"
            onClick={() => setSidebarOpen(false)}
          />
        )}

        {/* Sidebar */}
        <aside className={`
          fixed inset-y-0 left-0 z-[70] w-80 bg-white border-r border-gray-100 transform transition-transform duration-300 ease-out lg:translate-x-0 lg:static lg:inset-0 shadow-2xl lg:shadow-none
          ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        `}>
          <div className="flex flex-col h-full p-6">
            <div className="px-4 py-8 flex items-center justify-between mb-10">
              <div className="flex items-center gap-4 font-black text-3xl text-green-600 tracking-tighter">
                <div className="bg-green-600 text-white p-2.5 rounded-xl shadow-lg shadow-green-100">
                  <BookOpen size={32} />
                </div>
                <span>EduAI</span>
              </div>
              <button className="lg:hidden p-2 text-gray-400" onClick={() => setSidebarOpen(false)}>
                <X size={24} />
              </button>
            </div>

            <nav className="flex-1 space-y-3">
              <SidebarItem to="/" icon={LayoutDashboard} label="Dashboard" active={location.pathname === '/'} />
              <SidebarItem to="/documents" icon={FileText} label="Library" active={location.pathname.startsWith('/documents')} />
              <SidebarItem to="/flashcards" icon={BookOpen} label="Study Sets" active={location.pathname === '/flashcards'} />
              <SidebarItem to="/community" icon={Users} label="Community" active={location.pathname === '/community'} />
              <SidebarItem to="/profile" icon={UserIcon} label="Profile" active={location.pathname === '/profile'} />
            </nav>

            <div className="mt-auto pt-6 border-t border-gray-100">
              <button 
                onClick={logout}
                className="flex items-center gap-4 w-full px-6 py-4 text-gray-400 hover:bg-red-50 hover:text-red-600 rounded-2xl transition-all font-bold"
              >
                <LogOut size={22} />
                <span>Sign Out</span>
              </button>
            </div>
          </div>
        </aside>

        {/* Main Content */}
        <main className="flex-1 flex flex-col min-w-0 overflow-hidden relative">
          {/* Top Navbar */}
          <header className="h-24 bg-white border-b border-gray-100 flex items-center justify-between px-8 lg:px-12 z-40 shrink-0">
            <button className="lg:hidden p-3 text-gray-500 hover:bg-gray-100 rounded-2xl" onClick={() => setSidebarOpen(true)}>
              <Menu size={28} />
            </button>

            <div className="hidden md:flex items-center bg-gray-50 px-6 py-3.5 rounded-2xl border border-gray-100 w-[500px] focus-within:ring-4 focus-within:ring-green-50 focus-within:bg-white transition-all">
              <Search size={22} className="text-gray-400" />
              <input 
                type="text" 
                placeholder="Search across your library..." 
                className="bg-transparent border-none outline-none text-base px-3 w-full font-medium"
              />
            </div>

            <div className="flex items-center gap-6">
              <button className="p-3 text-gray-400 hover:bg-gray-50 hover:text-green-600 rounded-2xl relative transition-all">
                <Bell size={24} />
                <span className="absolute top-2.5 right-2.5 w-2.5 h-2.5 bg-green-500 rounded-full border-2 border-white"></span>
              </button>

              <div className="flex items-center gap-4 pl-6 border-l border-gray-100">
                <div className="text-right hidden sm:block">
                  <p className="text-base font-black text-gray-900 leading-tight">{user?.name}</p>
                  <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mt-0.5">Pro Student</p>
                </div>
                <img 
                  src={user?.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(user?.name || 'User')}&background=random`} 
                  alt="Avatar" 
                  className="w-14 h-14 rounded-[1.25rem] border-2 border-green-50 object-cover shadow-md ring-2 ring-white"
                />
              </div>
            </div>
          </header>

          {/* Page Content */}
          <div className="flex-1 overflow-y-auto p-8 lg:p-12 scroll-smooth custom-scrollbar">
            <Routes>
              <Route path="/" element={<Dashboard />} />
              <Route path="/documents" element={<Documents />} />
              <Route path="/documents/:id" element={<DocumentDetail />} />
              <Route path="/flashcards" element={<GlobalFlashcards />} />
              <Route path="/community" element={<CommunityChat />} />
              <Route path="/profile" element={<Profile />} />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          </div>
        </main>
      </div>
    </AuthContext.Provider>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

// Initialize the Gemini AI client using the API key directly from environment variables
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  generateSummary: async (text: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Summarize the following educational content in a structured way with key takeaways: ${text.substring(0, 15000)}`,
      config: {
        systemInstruction: "You are an expert academic summarizer. Provide a concise, professional summary with bullet points for key concepts."
      }
    });
    return response.text;
  },

  explainConcept: async (docText: string, concept: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Explain the concept of "${concept}" based on the provided document content. 
      Use clear formatting, examples, and if applicable, explain it step-by-step. 
      If there is code mentioned in the text related to this, include code snippets in markdown.

      DOCUMENT CONTENT:
      ${docText.substring(0, 15000)}`,
      config: {
        systemInstruction: "You are an expert tutor. Explain concepts deeply but simply. Use markdown for better readability (bold, lists, code blocks). If the concept isn't in the text, say so clearly."
      }
    });
    return response.text;
  },

  chatWithDocument: async (docText: string, history: {role: string, content: string}[], message: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(h => ({ 
          role: h.role === 'user' ? 'user' : 'model', 
          parts: [{ text: h.content }] 
        })),
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: `You are a dedicated Learning Assistant. Your primary goal is to help users understand the provided document.

GROUNDING RULES:
1. Answer questions using ONLY the information provided in the "DOCUMENT CONTENT" section below.
2. If the user asks something NOT covered in the document, do not just say "I don't know." Instead, politely explain that the document specifically covers [summarize document topics briefly] and does not mention [user's topic].
3. Use a helpful, educational tone. Break down complex ideas from the text.

DOCUMENT CONTENT:
${docText.substring(0, 20000)}`
      }
    });
    return response.text;
  },

  generateCommunityResponse: async (message: string, history: {userName: string, content: string}[]) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `The following is a community chat between students. Respond to the latest message as a helpful, expert Community Assistant.

      CHAT HISTORY:
      ${history.map(h => `${h.userName}: ${h.content}`).join('\n')}

      LATEST MESSAGE:
      ${message}`,
      config: {
        systemInstruction: "You are 'EduAI Bot', a verified academic assistant in a student community hub. Be encouraging, provide accurate info, and foster a collaborative learning environment. Keep responses concise (under 3 sentences)."
      }
    });
    return response.text;
  },

  generateFlashcards: async (text: string, count: number = 8) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create ${count} high-quality study flashcards from the following text. Focus on definitions, key dates, or core principles. Return as JSON. Text: ${text.substring(0, 10000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              answer: { type: Type.STRING },
              difficulty: { type: Type.STRING, enum: ['easy', 'medium', 'hard'] }
            },
            required: ['question', 'answer', 'difficulty']
          }
        }
      }
    });
    try {
      return JSON.parse(response.text || "[]");
    } catch {
      return [];
    }
  },

  generateQuiz: async (text: string, count: number = 5) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a ${count} question multiple-choice quiz from the following text. Each question should have 4 options and a detailed explanation. Return as JSON. Text: ${text.substring(0, 10000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctIndex: { type: Type.NUMBER },
              explanation: { type: Type.STRING }
            },
            required: ['question', 'options', 'correctIndex', 'explanation']
          }
        }
      }
    });
    try {
      return JSON.parse(response.text || "[]");
    } catch {
      return [];
    }
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../App';
import { storageService } from '../services/storageService';
import { geminiService } from '../services/geminiService';
import { CommunityMessage } from '../types';
import { Send, Users, Sparkles, MessageCircle, ShieldCheck, Zap } from 'lucide-react';

const CommunityChat: React.FC = () => {
  const { user } = useAuth();
  const [messages, setMessages] = useState<CommunityMessage[]>(storageService.getCommunityMessages());
  const [input, setInput] = useState('');
  const [isAiTyping, setIsAiTyping] = useState(false);
  const [isAiActive, setIsAiActive] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const interval = setInterval(() => {
      setMessages(storageService.getCommunityMessages());
    }, 2500);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isAiTyping]);

  const handleSend = async () => {
    if (!input.trim() || !user) return;

    const userMessage: CommunityMessage = {
      id: Math.random().toString(36).substr(2, 9),
      userId: user.id,
      userName: user.name,
      userAvatar: user.avatar || '',
      content: input,
      timestamp: Date.now()
    };

    // Save and update UI
    storageService.saveCommunityMessage(userMessage);
    setMessages(prev => [...prev, userMessage]);
    const currentInput = input;
    setInput('');

    // If AI is toggled or specific conditions met, get AI response
    if (isAiActive || input.toLowerCase().includes('@ai') || input.toLowerCase().includes('bot')) {
      setIsAiTyping(true);
      try {
        const history = messages.slice(-5).map(m => ({ userName: m.userName, content: m.content }));
        const aiResponse = await geminiService.generateCommunityResponse(currentInput, history);

        const aiMessage: CommunityMessage = {
          id: 'ai-bot-' + Date.now(),
          userId: 'edu-ai-bot',
          userName: 'EduAI Bot',
          userAvatar: '', // Will be handled by ID in UI
          content: aiResponse || "I'm listening! How can I help with your studies?",
          timestamp: Date.now()
        };

        storageService.saveCommunityMessage(aiMessage);
        setMessages(prev => [...prev, aiMessage]);
      } catch (e) {
        console.error("AI Community response failed", e);
      } finally {
        setIsAiTyping(false);
      }
    }
  };

  return (
    <div className="w-full max-w-5xl mx-auto h-[calc(100vh-12rem)] flex flex-col bg-white rounded-[3rem] border border-gray-100 shadow-xl overflow-hidden relative">
      {/* Chat Header */}
      <div className="bg-gradient-to-r from-green-600 to-green-800 p-8 text-white flex items-center justify-between shrink-0 shadow-lg relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-2xl -mr-16 -mt-16"></div>
        <div className="relative z-10 flex items-center gap-4">
          <div className="p-3 bg-white/20 backdrop-blur-md rounded-2xl border border-white/30">
            <Users size={32} />
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tight">Community Hub</h1>
            <p className="text-green-100 text-xs font-black uppercase tracking-[0.2em]">Real-time Academic Network</p>
          </div>
        </div>
        <div className="flex flex-col items-end gap-2 z-10">
          <div className="hidden md:flex items-center gap-3 bg-white/10 px-4 py-2 rounded-full border border-white/20 backdrop-blur-sm">
            <div className="w-2.5 h-2.5 bg-green-400 rounded-full animate-pulse shadow-[0_0_10px_rgba(74,222,128,0.8)]"></div>
            <span className="text-xs font-bold uppercase tracking-widest">1,204 Active Now</span>
          </div>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-10 space-y-8 bg-gray-50/30 custom-scrollbar">
        {messages.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center text-center opacity-40 grayscale pointer-events-none">
            <MessageCircle size={80} className="text-gray-200 mb-6" />
            <h3 className="text-2xl font-black text-gray-300">Start the conversation</h3>
            <p className="text-lg font-medium text-gray-400">Introduce yourself to your fellow scholars.</p>
          </div>
        ) : (
          messages.map((msg) => {
            const isBot = msg.userId === 'edu-ai-bot';
            const isMe = msg.userId === user?.id;

            return (
              <div key={msg.id} className={`flex gap-5 group ${isMe ? 'flex-row-reverse' : 'flex-row'} animate-in fade-in slide-in-from-bottom-2`}>
                <div className="shrink-0">
                  {isBot ? (
                    <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-indigo-600 to-purple-600 flex items-center justify-center text-white shadow-lg shadow-indigo-100 ring-2 ring-white">
                      <Zap size={24} />
                    </div>
                  ) : (
                    <img 
                      src={msg.userAvatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(msg.userName)}&background=random`} 
                      className="w-12 h-12 rounded-2xl shadow-md border-2 border-white group-hover:scale-110 transition-transform object-cover"
