import { User, Document, FlashcardSet, Quiz, Activity, ChatMessage, CommunityMessage } from '../types';

const STORAGE_KEYS = {
  USER: 'ai_learn_user',
  DOCS: 'ai_learn_docs',
  SETS: 'ai_learn_sets',
  QUIZZES: 'ai_learn_quizzes',
  ACTIVITY: 'ai_learn_activity',
  CHATS: 'ai_learn_chats',
  COMMUNITY_CHATS: 'ai_learn_community_chats'
};

export const storageService = {
  // Auth
  getUser: (): User | null => {
    const data = localStorage.getItem(STORAGE_KEYS.USER);
    return data ? JSON.parse(data) : null;
  },
  setUser: (user: User | null) => {
    if (user) localStorage.setItem(STORAGE_KEYS.USER, JSON.stringify(user));
    else localStorage.removeItem(STORAGE_KEYS.USER);
  },

  // Documents
  getDocuments: (): Document[] => {
    const data = localStorage.getItem(STORAGE_KEYS.DOCS);
    return data ? JSON.parse(data) : [];
  },
  saveDocument: (doc: Document) => {
    const docs = storageService.getDocuments();
    docs.push(doc);
    localStorage.setItem(STORAGE_KEYS.DOCS, JSON.stringify(docs));
    storageService.addActivity({
      id: Math.random().toString(36).substr(2, 9),
      type: 'upload',
      description: `Uploaded document: ${doc.title}`,
      timestamp: Date.now()
    });
  },
  updateDocument: (id: string, updates: Partial<Document>) => {
    const docs = storageService.getDocuments();
    const index = docs.findIndex(d => d.id === id);
    if (index !== -1) {
      docs[index] = { ...docs[index], ...updates };
      localStorage.setItem(STORAGE_KEYS.DOCS, JSON.stringify(docs));
    }
  },

  // Flashcards
  getFlashcardSets: (): FlashcardSet[] => {
    const data = localStorage.getItem(STORAGE_KEYS.SETS);
    return data ? JSON.parse(data) : [];
  },
  saveFlashcardSet: (set: FlashcardSet) => {
    const sets = storageService.getFlashcardSets();
    sets.push(set);
    localStorage.setItem(STORAGE_KEYS.SETS, JSON.stringify(sets));
    storageService.addActivity({
      id: Math.random().toString(36).substr(2, 9),
      type: 'flashcard',
      description: `Generated flashcards for: ${set.title}`,
      timestamp: Date.now()
    });
  },
  updateFlashcardSet: (id: string, updates: Partial<FlashcardSet>) => {
    const sets = storageService.getFlashcardSets();
    const index = sets.findIndex(s => s.id === id);
    if (index !== -1) {
      sets[index] = { ...sets[index], ...updates };
      localStorage.setItem(STORAGE_KEYS.SETS, JSON.stringify(sets));
    }
  },

  // Quizzes
  getQuizzes: (): Quiz[] => {
    const data = localStorage.getItem(STORAGE_KEYS.QUIZZES);
    return data ? JSON.parse(data) : [];
  },
  saveQuiz: (quiz: Quiz) => {
    const quizzes = storageService.getQuizzes();
    quizzes.push(quiz);
    localStorage.setItem(STORAGE_KEYS.QUIZZES, JSON.stringify(quizzes));
  },
  updateQuiz: (id: string, updates: Partial<Quiz>) => {
    const quizzes = storageService.getQuizzes();
    const index = quizzes.findIndex(q => q.id === id);
    if (index !== -1) {
      quizzes[index] = { ...quizzes[index], ...updates };
      localStorage.setItem(STORAGE_KEYS.QUIZZES, JSON.stringify(quizzes));
      if (updates.score !== undefined) {
        storageService.addActivity({
          id: Math.random().toString(36).substr(2, 9),
          type: 'quiz',
          description: `Completed quiz: ${quizzes[index].title} with score ${updates.score}%`,
          timestamp: Date.now()
        });
      }
    }
  },

  // Chats
  getChats: (docId: string): ChatMessage[] => {
    const chats = localStorage.getItem(`${STORAGE_KEYS.CHATS}_${docId}`);
    return chats ? JSON.parse(chats) : [];
  },
  saveChatMessage: (docId: string, message: ChatMessage) => {
    const chats = storageService.getChats(docId);
    chats.push(message);
    localStorage.setItem(`${STORAGE_KEYS.CHATS}_${docId}`, JSON.stringify(chats));
  },

  // Added Community Chat methods to fix errors in CommunityChat.tsx
  getCommunityMessages: (): CommunityMessage[] => {
    const data = localStorage.getItem(STORAGE_KEYS.COMMUNITY_CHATS);
    return data ? JSON.parse(data) : [];
  },
  saveCommunityMessage: (message: CommunityMessage) => {
    const messages = storageService.getCommunityMessages();
    messages.push(message);
    // Limit storage to the most recent 50 messages to keep local storage clean
    localStorage.setItem(STORAGE_KEYS.COMMUNITY_CHATS, JSON.stringify(messages.slice(-50)));
  },

  // Activity
  getActivities: (): Activity[] => {
    const data = localStorage.getItem(STORAGE_KEYS.ACTIVITY);
    return data ? JSON.parse(data) : [];
  },
  addActivity: (activity: Activity) => {
    const activities = storageService.getActivities();
    activities.unshift(activity);
    localStorage.setItem(STORAGE_KEYS.ACTIVITY, JSON.stringify(activities.slice(0, 20)));
  }
};

import { GoogleGenAI, Type } from "@google/genai";

// Initialize the Gemini AI client using the API key directly from environment variables
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  generateSummary: async (text: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Summarize the following educational content in a structured way with key takeaways: ${text.substring(0, 15000)}`,
      config: {
        systemInstruction: "You are an expert academic summarizer. Provide a concise, professional summary with bullet points for key concepts."
      }
    });
    return response.text;
  },

  explainConcept: async (docText: string, concept: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Explain the concept of "${concept}" based on the provided document content. 
      Use clear formatting, examples, and if applicable, explain it step-by-step. 
      If there is code mentioned in the text related to this, include code snippets in markdown.

      DOCUMENT CONTENT:
      ${docText.substring(0, 15000)}`,
      config: {
        systemInstruction: "You are an expert tutor. Explain concepts deeply but simply. Use markdown for better readability (bold, lists, code blocks). If the concept isn't in the text, say so clearly."
      }
    });
    return response.text;
  },

  chatWithDocument: async (docText: string, history: {role: string, content: string}[], message: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(h => ({ 
          role: h.role === 'user' ? 'user' : 'model', 
          parts: [{ text: h.content }] 
        })),
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: `You are a dedicated Learning Assistant. Your primary goal is to help users understand the provided document.

GROUNDING RULES:
1. Answer questions using ONLY the information provided in the "DOCUMENT CONTENT" section below.
2. If the user asks something NOT covered in the document, do not just say "I don't know." Instead, politely explain that the document specifically covers [summarize document topics briefly] and does not mention [user's topic].
3. Use a helpful, educational tone. Break down complex ideas from the text.

DOCUMENT CONTENT:
${docText.substring(0, 20000)}`
      }
    });
    return response.text;
  },

  generateFlashcards: async (text: string, count: number = 8) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create ${count} high-quality study flashcards from the following text. Focus on definitions, key dates, or core principles. Return as JSON. Text: ${text.substring(0, 10000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              answer: { type: Type.STRING },
              difficulty: { type: Type.STRING, enum: ['easy', 'medium', 'hard'] }
            },
            required: ['question', 'answer', 'difficulty']
          }
        }
      }
    });
    try {
      return JSON.parse(response.text || "[]");
    } catch {
      return [];
    }
  },

  generateQuiz: async (text: string, count: number = 5) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a ${count} question multiple-choice quiz from the following text. Each question should have 4 options and a detailed explanation. Return as JSON. Text: ${text.substring(0, 10000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctIndex: { type: Type.NUMBER },
              explanation: { type: Type.STRING }
            },
            required: ['question', 'options', 'correctIndex', 'explanation']
          }
        }
      }
    });
    try {
      return JSON.parse(response.text || "[]");
    } catch {
      return [];
    }
  },

  // Added generateCommunityResponse to fix property error in CommunityChat.tsx
  generateCommunityResponse: async (message: string, history: {userName: string, content: string}[]) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are participating in a group chat for students. 
      Recent conversation history:
      ${history.map(h => `${h.userName}: ${h.content}`).join('\n')}

      New User message: ${message}

      Respond as a helpful, encouraging AI study assistant named EduAI Bot. Keep responses concise and academic.`,
      config: {
        systemInstruction: "You are EduAI Bot, a friendly and knowledgeable AI participating in a student community chat. Your tone is supportive, academic, and professional yet approachable. Focus on helping students stay motivated and answering general academic questions."
      }
    });
    return response.text;
  }
};

