import { GoogleGenAI, Type } from "@google/genai";

// Initialize the Gemini AI client using the API key directly from environment variables
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  generateSummary: async (text: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Summarize the following educational content in a structured way with key takeaways: ${text.substring(0, 15000)}`,
      config: {
        systemInstruction: "You are an expert academic summarizer. Provide a concise, professional summary with bullet points for key concepts."
      }
    });
    return response.text;
  },

  explainConcept: async (docText: string, concept: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Explain the concept of "${concept}" based on the provided document content. 
      Use clear formatting, examples, and if applicable, explain it step-by-step. 
      If there is code mentioned in the text related to this, include code snippets in markdown.

      DOCUMENT CONTENT:
      ${docText.substring(0, 15000)}`,
      config: {
        systemInstruction: "You are an expert tutor. Explain concepts deeply but simply. Use markdown for better readability (bold, lists, code blocks). If the concept isn't in the text, say so clearly."
      }
    });
    return response.text;
  },

  chatWithDocument: async (docText: string, history: {role: string, content: string}[], message: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(h => ({ 
          role: h.role === 'user' ? 'user' : 'model', 
          parts: [{ text: h.content }] 
        })),
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: `You are a dedicated Learning Assistant. Your primary goal is to help users understand the provided document.

GROUNDING RULES:
1. Answer questions using ONLY the information provided in the "DOCUMENT CONTENT" section below.
2. If the user asks something NOT covered in the document, do not just say "I don't know." Instead, politely explain that the document specifically covers [summarize document topics briefly] and does not mention [user's topic].
3. Use a helpful, educational tone. Break down complex ideas from the text.

DOCUMENT CONTENT:
${docText.substring(0, 20000)}`
      }
    });
    return response.text;
  },

  generateFlashcards: async (text: string, count: number = 8) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze the following text and extract exactly ${count} of the most critical, high-yield concepts, definitions, and essential facts. 
      The goal is to provide a "last-minute revision" tool for students that covers the absolute most important topics likely to appear in an exam. 

      Requirements:
      1. Questions must be direct and focused on core principles.
      2. Answers must be concise, accurate, and easy to memorize.
      3. Focus on "must-know" information over trivial details.

      Return as JSON. Text: ${text.substring(0, 15000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING, description: 'High-impact revision question.' },
              answer: { type: Type.STRING, description: 'Concise, high-yield answer.' },
              difficulty: { type: Type.STRING, enum: ['easy', 'medium', 'hard'] }
            },
            required: ['question', 'answer', 'difficulty']
          }
        }
      }
    });
    try {
      return JSON.parse(response.text || "[]");
    } catch {
      return [];
    }
  },

  generateQuiz: async (text: string, count: number = 5) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a ${count} question multiple-choice quiz from the following text. Each question should have 4 options and a detailed explanation. Return as JSON. Text: ${text.substring(0, 10000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctIndex: { type: Type.NUMBER },
              explanation: { type: Type.STRING }
            },
            required: ['question', 'options', 'correctIndex', 'explanation']
          }
        }
      }
    });
    try {
      return JSON.parse(response.text || "[]");
    } catch {
      return [];
    }
  },

  // Added generateCommunityResponse to fix property error in CommunityChat.tsx
  generateCommunityResponse: async (message: string, history: {userName: string, content: string}[]) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are participating in a group chat for students. 
      Recent conversation history:
      ${history.map(h => `${h.userName}: ${h.content}`).join('\n')}

      New User message: ${message}

      Respond as a helpful, encouraging AI study assistant named EduAI Bot. Keep responses concise and academic.`,
      config: {
        systemInstruction: "You are EduAI Bot, a friendly and knowledgeable AI participating in a student community chat. Your tone is supportive, academic, and professional yet approachable. Focus on helping students stay motivated and answering general academic questions."
      }
    });
    return response.text;
  }
};

import React, { useState } from 'react';
import { BookOpen, Search, ArrowRight, BookMarked, MoreVertical, Plus, X, FileText, Sparkles, Zap, ChevronLeft, ChevronRight, Star, RotateCcw, CheckCircle, Hash } from 'lucide-react';
import { storageService } from '../services/storageService';
import { geminiService } from '../services/geminiService';
import { Link } from 'react-router-dom';
import { Document, FlashcardSet, Flashcard } from '../types';

const GlobalFlashcards: React.FC = () => {
  const [sets, setSets] = useState(storageService.getFlashcardSets());
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [selectedDoc, setSelectedDoc] = useState<Document | null>(null);
  const [flashcardCount, setFlashcardCount] = useState(8);

  // Study Mode State
  const [studyingSet, setStudyingSet] = useState<FlashcardSet | null>(null);
  const [cardIdx, setCardIdx] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  const documents = storageService.getDocuments();

  const handleGenerateSet = async () => {
    if (!selectedDoc) return;
    setIsGenerating(true);
    try {
      const cards = await geminiService.generateFlashcards(selectedDoc.extractedText, flashcardCount);
      const newSet: FlashcardSet = {
        id: Math.random().toString(36).substr(2, 9),
        documentId: selectedDoc.id,
        title: `Cards from ${selectedDoc.title}`,
        cards: cards.map((c: any) => ({
          ...c,
          id: Math.random().toString(36).substr(2, 9),
          isStarred: false,
          isReviewed: false
        })),
        createdAt: Date.now()
      };
      storageService.saveFlashcardSet(newSet);
      setSets(prev => [...prev, newSet]);
      setIsModalOpen(false);
      setSelectedDoc(null);
    } catch (error) {
      console.error("Generation failed", error);
      alert("Failed to generate flashcards.");
    } finally {
      setIsGenerating(false);
    }
  };

  const toggleStar = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!studyingSet) return;
    const updatedCards = [...studyingSet.cards];
    updatedCards[cardIdx].isStarred = !updatedCards[cardIdx].isStarred;
    const updatedSet = { ...studyingSet, cards: updatedCards };
    setStudyingSet(updatedSet);
    storageService.updateFlashcardSet(studyingSet.id, { cards: updatedCards });
    setSets(storageService.getFlashcardSets());
  };

  const markReviewed = () => {
    if (!studyingSet) return;
    const updatedCards = [...studyingSet.cards];
    updatedCards[cardIdx].isReviewed = true;
    const updatedSet = { ...studyingSet, cards: updatedCards };
    setStudyingSet(updatedSet);
    storageService.updateFlashcardSet(studyingSet.id, { cards: updatedCards });
    setSets(storageService.getFlashcardSets());
  };

  const filteredSets = sets.filter(s => s.title.toLowerCase().includes(searchQuery.toLowerCase()));

  // Render Study Mode UI
  if (studyingSet) {
    const currentCard = studyingSet.cards[cardIdx];
    const reviewedCount = studyingSet.cards.filter(c => c.isReviewed).length;
    const progress = Math.round((reviewedCount / studyingSet.cards.length) * 100);

    return (
      <div className="fixed inset-0 z-[110] bg-gray-50 flex flex-col animate-in fade-in duration-300">
        {/* Study Header */}
        <div className="h-24 bg-white border-b border-gray-100 flex items-center justify-between px-8 lg:px-12 shrink-0">
          <button 
            onClick={() => { setStudyingSet(null); setCardIdx(0); setIsFlipped(false); }}
            className="flex items-center gap-3 text-gray-500 hover:text-green-600 font-bold transition-all"
          >
            <ChevronLeft size={24} />
            Exit Study Mode
          </button>

          <div className="flex flex-col items-center">
            <h2 className="text-lg font-black text-gray-900 leading-tight">{studyingSet.title}</h2>
            <div className="flex items-center gap-2 mt-1">
              <span className="text-[10px] font-black text-gray-400 tracking-widest uppercase">PROGRESS</span>
              <div className="w-32 h-1.5 bg-gray-100 rounded-full overflow-hidden">
                <div className="h-full bg-green-500 transition-all duration-500" style={{ width: `${progress}%` }}></div>
              </div>
              <span className="text-[10px] font-black text-green-600 tracking-widest">{progress}%</span>
            </div>
          </div>

          <div className="w-32"></div> {/* Spacer */}
        </div>

        {/* Study Content */}
        <div className="flex-1 overflow-y-auto p-8 flex flex-col items-center justify-center gap-12">
          <div className="w-full max-w-3xl flex flex-col items-center gap-12">

            <div className="flex items-center justify-between w-full px-4">
              <div className="px-5 py-2 bg-green-100 text-green-800 rounded-full text-xs font-black uppercase tracking-[0.2em]">
                CARD {cardIdx + 1} OF {studyingSet.cards.length}
              </div>
              <div className="flex items-center gap-4">
                <button 
                  onClick={toggleStar}
                  className={`p-3 rounded-xl transition-all ${currentCard.isStarred ? 'bg-yellow-400 text-white shadow-lg' : 'bg-white text-gray-300 border border-gray-100'}`}
                >
                  <Star size={20} fill={currentCard.isStarred ? 'currentColor' : 'none'} />
                </button>
              </div>
            </div>

            {/* The Flashcard */}
            <div 
              className={`perspective-1000 w-full aspect-[16/10] cursor-pointer group ${isFlipped ? 'flashcard-flipped' : ''}`} 
              onClick={() => {
                setIsFlipped(!isFlipped);
                if (!isFlipped) markReviewed();
              }}
            >
              <div className="flashcard-inner relative w-full h-full text-center transition-transform duration-700 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] rounded-[3rem]">
                {/* Front */}
                <div className="flashcard-front absolute inset-0 w-full h-full bg-white border-2 border-gray-100 rounded-[3rem] flex flex-col items-center justify-center p-16 shadow-inner ring-8 ring-white">
                  <p className="text-gray-300 text-xs font-black uppercase tracking-[0.4em] mb-10">KNOWLEDGE PROMPT</p>
                  <h4 className="text-2xl lg:text-4xl font-black text-gray-800 leading-tight">{currentCard.question}</h4>
                  <div className="mt-auto flex items-center gap-3 text-xs font-black text-gray-400 uppercase tracking-widest bg-gray-50 px-8 py-3 rounded-full border border-gray-100">
