// Browser-compatible SHA-256 hashing
const hashPassword = async (password: string): Promise<string> => {
  const msgUint8 = new TextEncoder().encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgUint8);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
};

const SESSION_DURATION_MS = 24 * 60 * 60 * 1000; // 24 Hours

export const authService = {
  hashPassword,

  generateToken: (userId: string): { token: string; expiresAt: number } => {
    const expiresAt = Date.now() + SESSION_DURATION_MS;
    const payload = JSON.stringify({ userId, expiresAt });
    const token = btoa(payload); // Mock JWT
    return { token, expiresAt };
  },

  isSessionValid: (token: string | null): boolean => {
    if (!token) return false;
    try {
      const { expiresAt } = JSON.parse(atob(token));
      return Date.now() < expiresAt;
    } catch {
      return false;
    }
  }
};

import { User, Document, FlashcardSet, Quiz, Activity, ChatMessage, CommunityMessage } from '../types';

const STORAGE_KEYS = {
  CURRENT_USER: 'ai_learn_current_session',
  USERS_DB: 'ai_learn_users_db',
  DOCS: 'ai_learn_docs',
  SETS: 'ai_learn_sets',
  QUIZZES: 'ai_learn_quizzes',
  ACTIVITY: 'ai_learn_activity',
  CHATS: 'ai_learn_chats',
  COMMUNITY_CHATS: 'ai_learn_community_chats'
};

export const storageService = {
  // Auth & Multi-user DB
  getUsersDB: (): any[] => {
    const data = localStorage.getItem(STORAGE_KEYS.USERS_DB);
    return data ? JSON.parse(data) : [];
  },

  saveUserToDB: (user: any) => {
    const db = storageService.getUsersDB();
    const index = db.findIndex(u => u.email === user.email);
    if (index !== -1) db[index] = user;
    else db.push(user);
    localStorage.setItem(STORAGE_KEYS.USERS_DB, JSON.stringify(db));
  },

  getCurrentSession: (): User | null => {
    const data = localStorage.getItem(STORAGE_KEYS.CURRENT_USER);
    return data ? JSON.parse(data) : null;
  },

  setCurrentSession: (user: User | null) => {
    if (user) localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
  },

  // Documents (Scoped by current user)
  getDocuments: (): Document[] => {
    const user = storageService.getCurrentSession();
    const data = localStorage.getItem(STORAGE_KEYS.DOCS);
    const docs = data ? JSON.parse(data) : [];
    return user ? docs.filter((d: any) => d.userId === user.id) : [];
  },

  saveDocument: (doc: Document) => {
    const data = localStorage.getItem(STORAGE_KEYS.DOCS);
    const docs = data ? JSON.parse(data) : [];
    docs.push(doc);
    localStorage.setItem(STORAGE_KEYS.DOCS, JSON.stringify(docs));
    storageService.addActivity({
      id: Math.random().toString(36).substr(2, 9),
      type: 'upload',
      description: `Uploaded document: ${doc.title}`,
      timestamp: Date.now()
    });
  },

  updateDocument: (id: string, updates: Partial<Document>) => {
    const data = localStorage.getItem(STORAGE_KEYS.DOCS);
    const docs = data ? JSON.parse(data) : [];
    const index = docs.findIndex((d: any) => d.id === id);
    if (index !== -1) {
      docs[index] = { ...docs[index], ...updates };
      localStorage.setItem(STORAGE_KEYS.DOCS, JSON.stringify(docs));
    }
  },

  // Flashcards (Scoped)
  getFlashcardSets: (): FlashcardSet[] => {
    const data = localStorage.getItem(STORAGE_KEYS.SETS);
    const sets = data ? JSON.parse(data) : [];
    const docs = storageService.getDocuments();
    const docIds = new Set(docs.map(d => d.id));
    return sets.filter((s: any) => docIds.has(s.documentId));
  },

  saveFlashcardSet: (set: FlashcardSet) => {
    const data = localStorage.getItem(STORAGE_KEYS.SETS);
    const sets = data ? JSON.parse(data) : [];
    sets.push(set);
    localStorage.setItem(STORAGE_KEYS.SETS, JSON.stringify(sets));
    storageService.addActivity({
      id: Math.random().toString(36).substr(2, 9),
      type: 'flashcard',
      description: `Generated flashcards for: ${set.title}`,
      timestamp: Date.now()
    });
  },

  updateFlashcardSet: (id: string, updates: Partial<FlashcardSet>) => {
    const data = localStorage.getItem(STORAGE_KEYS.SETS);
    const sets = data ? JSON.parse(data) : [];
    const index = sets.findIndex((s: any) => s.id === id);
    if (index !== -1) {
      sets[index] = { ...sets[index], ...updates };
      localStorage.setItem(STORAGE_KEYS.SETS, JSON.stringify(sets));
    }
  },

  // Quizzes (Scoped)
  getQuizzes: (): Quiz[] => {
    const data = localStorage.getItem(STORAGE_KEYS.QUIZZES);
    const quizzes = data ? JSON.parse(data) : [];
    const docs = storageService.getDocuments();
    const docIds = new Set(docs.map(d => d.id));
    return quizzes.filter((q: any) => docIds.has(q.documentId));
  },

  saveQuiz: (quiz: Quiz) => {
    const quizzes = localStorage.getItem(STORAGE_KEYS.QUIZZES);
    const db = quizzes ? JSON.parse(quizzes) : [];
    db.push(quiz);
    localStorage.setItem(STORAGE_KEYS.QUIZZES, JSON.stringify(db));
  },

  updateQuiz: (id: string, updates: Partial<Quiz>) => {
    const data = localStorage.getItem(STORAGE_KEYS.QUIZZES);
    const quizzes = data ? JSON.parse(data) : [];
    const index = quizzes.findIndex((q: any) => q.id === id);
    if (index !== -1) {
      quizzes[index] = { ...quizzes[index], ...updates };
      localStorage.setItem(STORAGE_KEYS.QUIZZES, JSON.stringify(quizzes));
      if (updates.score !== undefined) {
        storageService.addActivity({
          id: Math.random().toString(36).substr(2, 9),
          type: 'quiz',
          description: `Completed quiz: ${quizzes[index].title} with score ${updates.score}%`,
          timestamp: Date.now()
        });
      }
    }
  },

  // Chats
  getChats: (docId: string): ChatMessage[] => {
    const chats = localStorage.getItem(`${STORAGE_KEYS.CHATS}_${docId}`);
    return chats ? JSON.parse(chats) : [];
  },

  saveChatMessage: (docId: string, message: ChatMessage) => {
    const chats = storageService.getChats(docId);
    chats.push(message);
    localStorage.setItem(`${STORAGE_KEYS.CHATS}_${docId}`, JSON.stringify(chats));
  },

  // Community Chat
  getCommunityMessages: (): CommunityMessage[] => {
    const data = localStorage.getItem(STORAGE_KEYS.COMMUNITY_CHATS);
    return data ? JSON.parse(data) : [];
  },

  saveCommunityMessage: (message: CommunityMessage) => {
    const messages = storageService.getCommunityMessages();
    messages.push(message);
    localStorage.setItem(STORAGE_KEYS.COMMUNITY_CHATS, JSON.stringify(messages.slice(-50)));
  },

  // Activity (Scoped)
  getActivities: (): Activity[] => {
    const user = storageService.getCurrentSession();
    const data = localStorage.getItem(STORAGE_KEYS.ACTIVITY);
    const activities = data ? JSON.parse(data) : [];
    // Activities aren't strictly scoped by documentId, we'll store them generally for now but could add userId to Activity type if needed.
    return activities;
  },

  addActivity: (activity: Activity) => {
    const activities = storageService.getActivities();
    activities.unshift(activity);
    localStorage.setItem(STORAGE_KEYS.ACTIVITY, JSON.stringify(activities.slice(0, 20)));
  }
};

import React, { useState } from 'react';
import { BookOpen, Mail, Lock, User as UserIcon, ArrowRight, Github, Sparkles, AlertCircle } from 'lucide-react';
import { authService } from '../services/authService';
import { storageService } from '../services/storageService';

interface AuthProps {
  onLogin: (email: string, name?: string, token?: string) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [username, setUsername] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    if (!email || !password) return;

    setIsLoading(true);
    try {
      const hash = await authService.hashPassword(password);
      const db = storageService.getUsersDB();

      if (isLogin) {
        // Sign In Flow
        const existingUser = db.find(u => u.email === email && u.passwordHash === hash);
        if (existingUser) {
          const { token } = authService.generateToken(existingUser.id);
          onLogin(email, existingUser.name, token);
        } else {
          setError("Invalid credentials. Please verify your email and secret key.");
        }
      } else {
        // Sign Up Flow
        if (db.some(u => u.email === email)) {
          setError("Identity already exists. Try signing in instead.");
        } else {
          const userId = Math.random().toString(36).substr(2, 9);
          const newUser = { id: userId, email, name: username, passwordHash: hash };
          storageService.saveUserToDB(newUser);
          const { token } = authService.generateToken(userId);
          onLogin(email, username, token);
        }
      }
    } catch (err) {
      setError("An unexpected security error occurred.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 selection:bg-green-100">
