import { User, Document, FlashcardSet, Quiz, Activity, ChatMessage, CommunityMessage } from '../types';

const STORAGE_KEYS = {
  CURRENT_USER: 'ai_learn_current_session',
  DOCS: 'ai_learn_docs',
  SETS: 'ai_learn_sets',
  QUIZZES: 'ai_learn_quizzes',
  ACTIVITY: 'ai_learn_activity',
  CHATS: 'ai_learn_chats',
  COMMUNITY: 'ai_learn_community'
};

export const storageService = {
  getCurrentSession: (): User | null => {
    const data = localStorage.getItem(STORAGE_KEYS.CURRENT_USER);
    return data ? JSON.parse(data) : null;
  },

  setCurrentSession: (user: User | null) => {
    if (user) localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
  },

  getDocuments: (): Document[] => {
    const data = localStorage.getItem(STORAGE_KEYS.DOCS);
    return data ? JSON.parse(data) : [];
  },

  saveDocument: (doc: Document) => {
    const docs = storageService.getDocuments();
    docs.push(doc);
    localStorage.setItem(STORAGE_KEYS.DOCS, JSON.stringify(docs));
    storageService.addActivity({
      id: Math.random().toString(36).substr(2, 9),
      type: 'upload',
      description: `Uploaded: ${doc.title}`,
      timestamp: Date.now()
    });
  },

  updateDocument: (id: string, updates: Partial<Document>) => {
    const docs = storageService.getDocuments();
    const index = docs.findIndex(d => d.id === id);
    if (index !== -1) {
      docs[index] = { ...docs[index], ...updates };
      localStorage.setItem(STORAGE_KEYS.DOCS, JSON.stringify(docs));
    }
  },

  getFlashcardSets: (): FlashcardSet[] => {
    const data = localStorage.getItem(STORAGE_KEYS.SETS);
    return data ? JSON.parse(data) : [];
  },

  saveFlashcardSet: (set: FlashcardSet) => {
    const sets = storageService.getFlashcardSets();
    sets.push(set);
    localStorage.setItem(STORAGE_KEYS.SETS, JSON.stringify(sets));
    storageService.addActivity({
      id: Math.random().toString(36).substr(2, 9),
      type: 'flashcard',
      description: `Created flashcards: ${set.title}`,
      timestamp: Date.now()
    });
  },

  // Added updateFlashcardSet to fix errors in DocumentDetail.tsx and GlobalFlashcards.tsx
  updateFlashcardSet: (id: string, updates: Partial<FlashcardSet>) => {
    const sets = storageService.getFlashcardSets();
    const index = sets.findIndex(s => s.id === id);
    if (index !== -1) {
      sets[index] = { ...sets[index], ...updates };
      localStorage.setItem(STORAGE_KEYS.SETS, JSON.stringify(sets));
    }
  },

  getQuizzes: (): Quiz[] => {
    const data = localStorage.getItem(STORAGE_KEYS.QUIZZES);
    return data ? JSON.parse(data) : [];
  },

  saveQuiz: (quiz: Quiz) => {
    const quizzes = storageService.getQuizzes();
    quizzes.push(quiz);
    localStorage.setItem(STORAGE_KEYS.QUIZZES, JSON.stringify(quizzes));
  },

  updateQuiz: (id: string, updates: Partial<Quiz>) => {
    const quizzes = storageService.getQuizzes();
    const index = quizzes.findIndex(q => q.id === id);
    if (index !== -1) {
      quizzes[index] = { ...quizzes[index], ...updates };
      localStorage.setItem(STORAGE_KEYS.QUIZZES, JSON.stringify(quizzes));
    }
  },

  getChats: (docId: string): ChatMessage[] => {
    const chats = localStorage.getItem(`${STORAGE_KEYS.CHATS}_${docId}`);
    return chats ? JSON.parse(chats) : [];
  },

  saveChatMessage: (docId: string, message: ChatMessage) => {
    const chats = storageService.getChats(docId);
    chats.push(message);
    localStorage.setItem(`${STORAGE_KEYS.CHATS}_${docId}`, JSON.stringify(chats));
  },

  // Added getCommunityMessages to fix errors in CommunityChat.tsx
  getCommunityMessages: (): CommunityMessage[] => {
    const data = localStorage.getItem(STORAGE_KEYS.COMMUNITY);
    return data ? JSON.parse(data) : [];
  },

  // Added saveCommunityMessage to fix errors in CommunityChat.tsx
  saveCommunityMessage: (message: CommunityMessage) => {
    const messages = storageService.getCommunityMessages();
    messages.push(message);
    // Keep only the last 50 messages to prevent LocalStorage bloat
    localStorage.setItem(STORAGE_KEYS.COMMUNITY, JSON.stringify(messages.slice(-50)));
  },

  getActivities: (): Activity[] => {
    const data = localStorage.getItem(STORAGE_KEYS.ACTIVITY);
    return data ? JSON.parse(data) : [];
  },

  addActivity: (activity: Activity) => {
    const activities = storageService.getActivities();
    activities.unshift(activity);
    localStorage.setItem(STORAGE_KEYS.ACTIVITY, JSON.stringify(activities.slice(0, 10)));
  }
};

import { GoogleGenAI, Type } from "@google/genai";

// Initialize the Gemini AI client using the API key directly from environment variables
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const geminiService = {
  generateSummary: async (text: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Summarize the following educational content in a structured way with key takeaways: ${text.substring(0, 15000)}`,
      config: {
        systemInstruction: "You are an expert academic summarizer. Provide a concise, professional summary with bullet points for key concepts."
      }
    });
    return response.text;
  },

  explainConcept: async (docText: string, concept: string) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Explain the concept of "${concept}" based on the provided document content. 
      Use clear formatting, examples, and if applicable, explain it step-by-step. 
      If there is code mentioned in the text related to this, include code snippets in markdown.

      DOCUMENT CONTENT:
      ${docText.substring(0, 15000)}`,
      config: {
        systemInstruction: "You are an expert tutor. Explain concepts deeply but simply. Use markdown for better readability (bold, lists, code blocks). If the concept isn't in the text, say so clearly."
      }
    });
    return response.text;
  },

  // NEW: Streaming Chat Implementation
  chatWithDocumentStream: async (docText: string, history: {role: string, content: string}[], message: string, onChunk: (text: string) => void) => {
    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(h => ({ 
          role: h.role === 'user' ? 'user' : 'model', 
          parts: [{ text: h.content }] 
        })),
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: `You are a world-class Learning Assistant. Your primary goal is to help users master the provided document.

CHAT CHARACTERISTICS:
1. Tone: Encouraging, professional, and intellectually stimulating.
2. Grounding: Answer using the "DOCUMENT CONTENT" provided. 
3. Flexibility: If a user asks a meta-question about learning or asks for an analogy not in the text, you may provide it to help them understand, but always link it back to the core document facts.
4. Formatting: Use Markdown (bold, lists) for clarity.

DOCUMENT CONTENT:
${docText.substring(0, 25000)}`
      }
    });

    let fullText = "";
    for await (const chunk of responseStream) {
      const chunkText = chunk.text;
      if (chunkText) {
        fullText += chunkText;
        onChunk(fullText);
      }
    }
    return fullText;
  },

  generateFlashcards: async (text: string, count: number = 8) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze the following text and extract exactly ${count} of the most critical, high-yield concepts, definitions, and essential facts. 
      The goal is to provide a "last-minute revision" tool for students that covers the absolute most important topics likely to appear in an exam. 

      Requirements:
      1. Questions must be direct and focused on core principles.
      2. Answers must be concise, accurate, and easy to memorize.
      3. Focus on "must-know" information over trivial details.

      Return as JSON. Text: ${text.substring(0, 15000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING, description: 'High-impact revision question.' },
              answer: { type: Type.STRING, description: 'Concise, high-yield answer.' },
              difficulty: { type: Type.STRING, enum: ['easy', 'medium', 'hard'] }
            },
            required: ['question', 'answer', 'difficulty']
          }
        }
      }
    });
    try {
      return JSON.parse(response.text || "[]");
    } catch {
      return [];
    }
  },

  generateQuiz: async (text: string, count: number = 5) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a ${count} question multiple-choice quiz from the following text. Each question should have 4 options and a detailed explanation. Return as JSON. Text: ${text.substring(0, 10000)}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              correctIndex: { type: Type.NUMBER },
              explanation: { type: Type.STRING }
            },
            required: ['question', 'options', 'correctIndex', 'explanation']
          }
        }
      }
    });
    try {
      return JSON.parse(response.text || "[]");
    } catch {
      return [];
    }
  },

  generateCommunityResponse: async (message: string, history: {userName: string, content: string}[]) => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are participating in a group chat for students. 
      Recent conversation history:
      ${history.map(h => `${h.userName}: ${h.content}`).join('\n')}

      New User message: ${message}

      Respond as a helpful, encouraging AI study assistant named EduAI Bot. Keep responses concise and academic.`,
      config: {
        systemInstruction: "You are EduAI Bot, a friendly and knowledgeable AI participating in a student community chat. Your tone is supportive, academic, and professional yet approachable. Focus on helping students stay motivated and answering general academic questions."
      }
    });
    return response.text;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useParams, Link } from 'react-router-dom';
import { 
  FileText, MessageSquare, Sparkles, BookOpen, Target, 
  ChevronLeft, Send, Sparkle, Star, CheckCircle, 
  RotateCcw, ChevronRight, XCircle, FileSearch, Download, AlertCircle, HelpCircle, X, Hash
} from 'lucide-react';
import { storageService } from '../services/storageService';
import { geminiService } from '../services/geminiService';
import { Document, ChatMessage, FlashcardSet, Quiz } from '../types';

const DocumentDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const [doc, setDoc] = useState<Document | null>(null);
  const [activeTab, setActiveTab] = useState<'content' | 'chat' | 'actions' | 'flashcards' | 'quiz'>('content');
  const [contentView, setContentView] = useState<'pdf' | 'text'>('pdf');
  const [isLoading, setIsLoading] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [pdfBlobUrl, setPdfBlobUrl] = useState<string | null>(null);

  // Chat State
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  // AI Actions State
  const [conceptInput, setConceptInput] = useState('');
  const [explanation, setExplanation] = useState<string | null>(null);

  // Flashcard State
  const [flashcardSets, setFlashcardSets] = useState<FlashcardSet[]>([]);
  const [currentSetIdx, setCurrentSetIdx] = useState(0);
  const [cardIdx, setCardIdx] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [flashcardCount, setFlashcardCount] = useState(8);

  // Quiz State
  const [activeQuiz, setActiveQuiz] = useState<Quiz | null>(null);
  const [quizStep, setQuizStep] = useState(0);
  const [userAnswers, setUserAnswers] = useState<number[]>([]);
  const [showResults, setShowResults] = useState(false);
  const [quizQuestionCount, setQuizQuestionCount] = useState(5);

  useEffect(() => {
    if (id) {
      const found = storageService.getDocuments().find(d => d.id === id);
      if (found) {
        setDoc(found);
        setMessages(storageService.getChats(id));
        setFlashcardSets(storageService.getFlashcardSets().filter(s => s.documentId === id));

        // Create Blob URL for PDF
        if (found.filePath && found.filePath.startsWith('data:application/pdf;base64,')) {
          try {
            const base64Content = found.filePath.split(',')[1];
            const binaryString = window.atob(base64Content);
            const bytes = new Uint8Array(binaryString.length);
            for (let i = 0; i < binaryString.length; i++) {
              bytes[i] = binaryString.charCodeAt(i);
            }
            const blob = new Blob([bytes], { type: 'application/pdf' });
            const url = URL.createObjectURL(blob);
            setPdfBlobUrl(url);
          } catch (e) {
            console.error("Error creating PDF blob", e);
            setPdfBlobUrl(found.filePath);
          }
        } else {
          setPdfBlobUrl(found.filePath);
        }
      }
    }

    return () => {
      if (pdfBlobUrl && pdfBlobUrl.startsWith('blob:')) {
        URL.revokeObjectURL(pdfBlobUrl);
      }
    };
  }, [id]);

  // Smoother scrolling for streaming
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSendMessage = async () => {
    if (!input.trim() || !doc || isTyping) return;

    const currentInput = input;
    const userMsg: ChatMessage = { role: 'user', content: currentInput, timestamp: Date.now() };

    // 1. Update UI with user message
    setMessages(prev => [...prev, userMsg]);
    storageService.saveChatMessage(doc.id, userMsg);
    setInput('');
    setIsTyping(true);

    try {
      const history = messages.map(m => ({ role: m.role, content: m.content }));

      // 2. Prepare a placeholder AI message
      const aiMsg: ChatMessage = { role: 'model', content: "", timestamp: Date.now() };
      setMessages(prev => [...prev, aiMsg]);

      // 3. Start streaming
      const finalResponse = await geminiService.chatWithDocumentStream(
        doc.extractedText, 
        history, 
        currentInput, 
        (chunkedText) => {
          // Update the last message (the placeholder) with the accumulated chunks
          setMessages(prev => {
            const updated = [...prev];
            updated[updated.length - 1] = { ...updated[updated.length - 1], content: chunkedText };
            return updated;
          });
        }
      );

      // 4. Save the finalized message to storage
      storageService.saveChatMessage(doc.id, { role: 'model', content: finalResponse, timestamp: Date.now() });

    } catch (error) {
      console.error("Chat failed", error);
      const errorMsg: ChatMessage = { role: 'model', content: "Sorry, I encountered an error while processing your request.", timestamp: Date.now() };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsTyping(false);
    }
  };

  const generateSummary = async () => {
    if (!doc) return;
    setIsLoading(true);
    try {
      const summary = await geminiService.generateSummary(doc.extractedText);
      storageService.updateDocument(doc.id, { summary: summary || "" });
      setDoc(prev => prev ? { ...prev, summary: summary || "" } : null);
    } catch (error) {
      console.error("Summary failed", error);
    } finally {
      setIsLoading(false);
    }
  };

  const explainConcept = async () => {
    if (!doc || !conceptInput.trim()) return;
    setIsLoading(true);
    setExplanation(null);
    try {
      const result = await geminiService.explainConcept(doc.extractedText, conceptInput);
      setExplanation(result || "Could not generate explanation.");
      storageService.addActivity({
        id: Math.random().toString(36).substr(2, 9),
        type: 'concept',
        description: `Asked for explanation of: ${conceptInput}`,
        timestamp: Date.now()
      });
    } catch (error) {
      console.error("Explanation failed", error);
    } finally {
      setIsLoading(false);
    }
  };

  const generateFlashcards = async () => {
    if (!doc) return;
    setIsLoading(true);
    try {
      const cards = await geminiService.generateFlashcards(doc.extractedText, flashcardCount);
      const newSet: FlashcardSet = {
        id: Math.random().toString(36).substr(2, 9),
        documentId: doc.id,
        title: `Cards from ${doc.title}`,
        cards: cards.map((c: any) => ({
          ...c,
          id: Math.random().toString(36).substr(2, 9),
          isStarred: false,
          isReviewed: false
        })),
        createdAt: Date.now()
      };
      storageService.saveFlashcardSet(newSet);
      setFlashcardSets(prev => [...prev, newSet]);
    } catch (error) {
      console.error("Flashcard generation failed", error);
    } finally {
      setIsLoading(false);
    }
  };

  const generateQuiz = async () => {
    if (!doc) return;
    setIsLoading(true);
    try {
      const questions = await geminiService.generateQuiz(doc.extractedText, quizQuestionCount);
      const newQuiz: Quiz = {
        id: Math.random().toString(36).substr(2, 9),
        documentId: doc.id,
        title: `Quiz for ${doc.title}`,
        questions: questions.map((q: any) => ({ ...q, id: Math.random().toString(36).substr(2, 9) }))
      };
      storageService.saveQuiz(newQuiz);
      setActiveQuiz(newQuiz);
      setUserAnswers(new Array(newQuiz.questions.length).fill(-1));
      setQuizStep(0);
      setShowResults(false);
    } catch (error) {
      console.error("Quiz generation failed", error);
    } finally {
      setIsLoading(false);
    }
  };

  const submitQuiz = () => {
    if (!activeQuiz) return;
    let correct = 0;
    activeQuiz.questions.forEach((q, i) => {
      if (userAnswers[i] === q.correctIndex) correct++;
    });
    const score = Math.round((correct / activeQuiz.questions.length) * 100);
    storageService.updateQuiz(activeQuiz.id, { score, attemptedAt: Date.now() });
    setShowResults(true);
  };

  if (!doc) return <div className="p-8 text-center font-bold">Document not found.</div>;

  return (
    <div className="w-full max-w-[1800px] mx-auto h-full flex flex-col gap-6">
