              <Route path="/flashcards" element={<GlobalFlashcards />} />
              <Route path="/profile" element={<Profile />} />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          </div>
        </main>
      </div>
    </AuthContext.Provider>
  );
};

export default App;
